// Keyless address autocomplete via Photon (OpenStreetMap). No API key / billing.
// Results are biased toward the Bay Area; coordinates come straight from the suggestion.

import { TtlCache, createDeduper } from './cache'

export interface GeoResult {
  label: string
  lng: number
  lat: number
}

// Bias center (roughly mid-Bay) so local addresses rank first.
const BIAS = { lat: 37.66, lon: -122.1 }

// Cache successful suggestion lists by normalized query so backspace-retype and
// repeated lookups don't re-hit Photon. Short TTL — addresses rarely change but
// we don't want a long-lived stale list.
const geoCache = new TtlCache<GeoResult[]>(80, 10 * 60_000)
const dedupeGeo = createDeduper(geoCache)

interface PhotonProps {
  name?: string
  housenumber?: string
  street?: string
  city?: string
  district?: string
  state?: string
  postcode?: string
}

function labelOf(p: PhotonProps): string {
  const line1 = [p.housenumber, p.street].filter(Boolean).join(' ') || p.name || ''
  const line2 = [p.city || p.district, p.state].filter(Boolean).join(', ')
  return [line1, line2].filter(Boolean).join(', ') || p.name || 'Unknown location'
}

export async function searchAddresses(query: string, signal?: AbortSignal): Promise<GeoResult[]> {
  const q = query.trim()
  if (q.length < 3) return []
  const url = `https://photon.komoot.io/api?q=${encodeURIComponent(q)}&limit=6&lat=${BIAS.lat}&lon=${BIAS.lon}`
  try {
    return await dedupeGeo(q.toLowerCase(), async () => {
      const res = await fetch(url, { signal })
      // Throw on transient HTTP failure so the empty result is NOT cached.
      if (!res.ok) throw new Error(`geocode http ${res.status}`)
      const j = (await res.json()) as { features?: { geometry?: { coordinates?: number[] }; properties?: PhotonProps }[] }
      return (j.features ?? [])
        .filter((f) => Array.isArray(f.geometry?.coordinates) && f.geometry!.coordinates!.length >= 2)
        .map((f) => ({ label: labelOf(f.properties ?? {}), lng: f.geometry!.coordinates![0], lat: f.geometry!.coordinates![1] }))
    })
  } catch {
    // AbortError or thrown HTTP error — return empty, nothing cached.
    return []
  }
}

/** Exposed for tests. */
export const __geoCache = geoCache
