// Pure view-model derivation for the "Flex Lane Map" redesign. Ported from the
// design's renderVals() but with the live/sample/estimate distinction handled
// honestly (the design collapsed "sample" into "estimate"). No React, no DOM —
// every function takes the time it needs, so it stays deterministic + testable.
import type { Corridor, FareBreakdown, Occupancy, RateSourceKind } from './types'
import { computeFare, congestionFactor, estimatedZonePrice, money, occupancyMultiplier, tollingStatus } from './pricing'
import type { LiveResponse } from './liveClient'
import { resolveDirection } from './liveClient'
import { corridorById } from '../data/corridors'
import type { LaneMatch } from './matchLanes'
import { expressSpeedMph, generalSpeedMph, minutesSaved, savedLabel } from './timeSavings'

// — palette (mirrors tokens.css; kept here so the view model is self-contained) —
export const C = {
  green: '#35d07a',
  greenDeep: '#36d07a',
  greenSoft: '#9be8bf',
  amber: '#ffb000',
  amberDeep: '#ffc24d',
  idle: '#6b7280',
  ink1: '#f6f5f0',
  ink2: '#b3afa3',
  ink3: '#8a8576',
  line2: '#2c323b',
  lineStrong: '#3a4049',
} as const

export type BadgeKind = 'live' | 'sample' | 'estimate' | 'open'

export interface ReadoutBadge {
  text: string
  color: string
  bg: string
  border: string
  pulse: boolean
}
export interface BreakdownRow {
  label: string
  amount: string
  labelColor: string
  amountColor: string
}
export interface ReadoutVM {
  readoutLabel: string
  priceText: string
  priceColor: string
  priceGlow: string
  priceSize: number // px
  isFree: boolean
  freeReason: string
  badge: ReadoutBadge
  breakdown: BreakdownRow[]
  totalLabel: string
  tolledReason: string
}

/** The answer-first DMS readout: label, badge, price, breakdown, reason. */
export function buildReadout(fare: FareBreakdown, tolled: { tolled: boolean; reason: string }, occupancy: Occupancy): ReadoutVM {
  const isTolled = tolled.tolled
  const isFreeCarpool = isTolled && fare.netToll === 0
  const isFree = !isTolled || isFreeCarpool
  const source = fare.source

  let badge: ReadoutBadge
  const liveBadge: ReadoutBadge = { text: 'LIVE · 511', color: C.greenDeep, bg: 'rgba(54,208,122,.12)', border: 'rgba(54,208,122,.35)', pulse: true }
  const sampleBadge: ReadoutBadge = { text: 'SAMPLE · 511', color: C.greenDeep, bg: 'rgba(54,208,122,.1)', border: 'rgba(54,208,122,.28)', pulse: false }
  const estBadge: ReadoutBadge = { text: 'ESTIMATE', color: '#b9b3a3', bg: 'rgba(255,255,255,.05)', border: 'rgba(255,255,255,.12)', pulse: false }
  const openBadge: ReadoutBadge = { text: 'OPEN', color: '#b9b3a3', bg: 'rgba(255,255,255,.05)', border: 'rgba(255,255,255,.12)', pulse: false }

  let priceText: string, priceColor: string, priceGlow: string, readoutLabel: string

  if (!isTolled) {
    priceText = 'FREE'
    priceColor = C.greenDeep
    priceGlow = '0 0 18px rgba(54,208,122,.3)'
    readoutLabel = 'Open to all'
    badge = openBadge
  } else {
    priceText = money(fare.netToll)
    if (isFreeCarpool) {
      priceColor = C.greenDeep
      priceGlow = '0 0 18px rgba(54,208,122,.3)'
      readoutLabel = 'Carpool toll'
    } else {
      priceColor = C.amber
      priceGlow = '0 0 18px rgba(255,176,0,.35),0 0 2px rgba(255,176,0,.55)'
      readoutLabel = source === 'live' ? 'Toll now' : source === 'sample' ? 'Sample feed' : 'Estimated toll'
    }
    badge = source === 'live' ? liveBadge : source === 'sample' ? sampleBadge : estBadge
  }

  const priceSize = isFree && !isFreeCarpool ? 46 : priceText.length > 5 ? 46 : 56
  const postedColor = (s: RateSourceKind) => (s === 'live' || s === 'sample' ? C.greenSoft : '#d9d2c0')

  let breakdown: BreakdownRow[]
  if (isTolled) {
    breakdown = fare.zones.map((z) => ({
      label: `${z.fromLabel} → ${z.toLabel}`,
      amount: money(z.price),
      labelColor: C.ink3,
      amountColor: postedColor(z.source),
    }))
    if (fare.occupancyMultiplier === 0 && fare.grossToll > 0) {
      breakdown.push({
        label: occupancy === 'two' ? '2-person carpool · free' : '3+ carpool · free',
        amount: `−${money(fare.grossToll)}`,
        labelColor: C.greenDeep,
        amountColor: C.greenDeep,
      })
    } else if (fare.occupancyMultiplier === 0.5) {
      breakdown.push({
        label: '2-person carpool · −50%',
        amount: `−${money(fare.grossToll - fare.netToll)}`,
        labelColor: C.greenDeep,
        amountColor: C.greenDeep,
      })
    }
  } else {
    breakdown = [{ label: 'Lanes open to all', amount: '$0.00', labelColor: C.ink3, amountColor: '#d9d2c0' }]
  }

  return {
    readoutLabel,
    priceText,
    priceColor,
    priceGlow,
    priceSize,
    isFree,
    freeReason: !isTolled ? tolled.reason : fare.freeReason ?? '',
    badge,
    breakdown,
    totalLabel: occupancy === 'solo' ? 'Solo total' : 'Your total',
    tolledReason: tolled.reason,
  }
}

/**
 * Answer-first readout for a planned ADDRESS trip: the modeled toll summed across
 * every express lane the OSRM route actually uses (via matchLanes). Always an
 * estimate — trip tolls are modeled per-zone, not posted-price.
 */
export function buildTripReadout(matches: LaneMatch[], occupancy: Occupancy, date: Date): ReadoutVM {
  const factor = congestionFactor(date)
  const breakdown: BreakdownRow[] = []
  let net = 0
  let gross = 0
  let anyTolled = false
  for (const m of matches) {
    const c = corridorById(m.corridorId)
    if (!c) continue
    const tolled = tollingStatus(c, date).tolled
    const g = m.zones * estimatedZonePrice(c, factor)
    const n = tolled ? g * occupancyMultiplier(c, occupancy) : 0
    if (tolled) {
      anyTolled = true
      gross += g
    }
    net += n
    breakdown.push({
      // Itemize the GROSS per-lane price so the lane rows minus the single carpool
      // discount row below reconcile to the net headline total (mirrors buildReadout).
      label: `${c.routeBadge} · ${m.entryLabel} → ${m.exitLabel}`,
      amount: tolled ? money(Math.round(g * 100) / 100) : 'free',
      labelColor: C.ink3,
      amountColor: tolled ? '#d9d2c0' : C.greenDeep,
    })
  }
  net = Math.round(net * 100) / 100
  gross = Math.round(gross * 100) / 100
  const noLanes = breakdown.length === 0
  const isFreeCarpool = anyTolled && net === 0
  if (occupancy !== 'solo' && anyTolled && gross > net) {
    breakdown.push({
      label: occupancy === 'two' ? 'Carpool · −50%' : 'Carpool · free',
      amount: `−${money(gross - net)}`,
      labelColor: C.greenDeep,
      amountColor: C.greenDeep,
    })
  }
  if (noLanes) breakdown.push({ label: 'No express lanes on this route', amount: '$0.00', labelColor: C.ink3, amountColor: '#d9d2c0' })

  const estBadge: ReadoutBadge = { text: 'ESTIMATE', color: '#b9b3a3', bg: 'rgba(255,255,255,.05)', border: 'rgba(255,255,255,.12)', pulse: false }
  const openBadge: ReadoutBadge = { text: noLanes ? 'NONE' : 'OPEN', color: '#b9b3a3', bg: 'rgba(255,255,255,.05)', border: 'rgba(255,255,255,.12)', pulse: false }

  let priceText: string, priceColor: string, priceGlow: string, readoutLabel: string, badge: ReadoutBadge
  if (noLanes) {
    priceText = '$0.00'
    priceColor = C.greenDeep
    priceGlow = '0 0 18px rgba(54,208,122,.3)'
    readoutLabel = 'No express lanes'
    badge = openBadge
  } else if (!anyTolled) {
    priceText = 'FREE'
    priceColor = C.greenDeep
    priceGlow = '0 0 18px rgba(54,208,122,.3)'
    readoutLabel = 'Open now'
    badge = openBadge
  } else if (isFreeCarpool) {
    priceText = '$0.00'
    priceColor = C.greenDeep
    priceGlow = '0 0 18px rgba(54,208,122,.3)'
    readoutLabel = 'Carpool trip'
    badge = estBadge
  } else {
    priceText = money(net)
    priceColor = C.amber
    priceGlow = '0 0 18px rgba(255,176,0,.35),0 0 2px rgba(255,176,0,.55)'
    readoutLabel = 'Trip · express lanes'
    badge = estBadge
  }

  const lanes = breakdown.length === 0 || noLanes ? 0 : matches.length
  return {
    readoutLabel,
    priceText,
    priceColor,
    priceGlow,
    priceSize: priceText.length > 5 ? 46 : 56,
    isFree: noLanes || !anyTolled || isFreeCarpool,
    freeReason: '',
    badge,
    breakdown,
    totalLabel: 'Trip total',
    tolledReason: noLanes
      ? 'This driving route does not use any express lane.'
      : `Modeled across ${lanes} express lane${lanes === 1 ? '' : 's'} the route uses — the posted price at the gantry governs.`,
  }
}

export interface StopVM {
  i: number
  label: string
  dotSize: number // px
  dotBg: string
  dotBorder: string
  dotShadow: string
  connTop: string
  connBot: string
  labelColor: string
  labelWeight: number
  tag: string
  tagColor: string
}

/** The "tap two stops" trip ribbon: entry green, exit amber, span highlighted. */
export function buildStops(points: { label: string }[], entry: number, exit: number): StopVM[] {
  const dim = C.line2
  const last = points.length - 1
  return points.map((p, i) => {
    const isEntry = i === entry
    const isExit = i === exit
    const active = isEntry || isExit || (i > entry && i < exit)
    const topHi = i > entry && i <= exit
    const botHi = i >= entry && i < exit
    return {
      i,
      label: p.label,
      dotSize: isEntry || isExit ? 15 : 10,
      dotBg: isEntry ? C.green : isExit ? C.amber : active ? '#1b2027' : '#14181e',
      dotBorder: isEntry ? C.green : isExit ? C.amber : active ? C.lineStrong : dim,
      dotShadow: isEntry ? '0 0 10px rgba(53,208,122,.6)' : isExit ? '0 0 10px rgba(255,176,0,.6)' : 'none',
      connTop: i === 0 ? 'transparent' : topHi ? C.amber : dim,
      connBot: i === last ? 'transparent' : botHi ? C.green : dim,
      labelColor: active ? C.ink1 : C.ink3,
      labelWeight: isEntry || isExit ? 600 : 400,
      tag: isEntry ? 'START' : isExit ? 'EXIT' : '',
      tagColor: isEntry ? C.green : C.amber,
    }
  })
}

export interface OccOptionVM {
  id: Occupancy
  icon: string
  title: string
  sub: string
  selected: boolean
  bg: string
  border: string
  titleColor: string
  subColor: string
}

/** Occupancy chooser (solo / 2-person / 3+) with the corridor's carpool rule. */
export function buildOccOptions(corridor: Corridor, occupancy: Occupancy): OccOptionVM[] {
  const def: { id: Occupancy; icon: string; title: string; sub: string }[] = [
    { id: 'solo', icon: '🧍', title: 'Solo', sub: 'Flex 1' },
    { id: 'two', icon: '🧑‍🤝‍🧑', title: '2 people', sub: corridor.twoPersonRule === 'free' ? 'free' : 'half' },
    { id: 'threePlus', icon: '👨‍👩‍👧', title: '3+ / moto', sub: 'free' },
  ]
  return def.map((o) => {
    const on = occupancy === o.id
    const accent = o.id === 'solo' ? C.amber : C.green
    return {
      ...o,
      selected: on,
      bg: on ? (o.id === 'solo' ? 'rgba(255,176,0,.1)' : 'rgba(53,208,122,.1)') : '#14181e',
      border: on ? `1.5px solid ${accent}` : '1px solid #2c323b',
      titleColor: on ? (o.id === 'solo' ? C.amberDeep : C.greenDeep) : '#ecebe5',
      subColor: on ? (o.id === 'solo' ? '#d9b25a' : C.greenDeep) : C.ink3,
    }
  })
}

export function occupancyRuleHint(corridor: Corridor): string {
  return corridor.twoPersonRule === 'free'
    ? `On ${corridor.route}, 2-person carpools ride free. 3+, motorcycles, vanpools & transit are always free.`
    : `On ${corridor.route}, 2-person carpools pay half price. 3+, motorcycles, vanpools & transit are always free.`
}

/** SVG area-chart of the typical toll across the tolling day (5a–8p). */
export function buildDepartureCurve(corridor: Corridor, zonesCount: number, baseDate: Date): { path: string; area: string } {
  const N = 46
  const zones = Math.max(1, zonesCount)
  const maxTrip = corridor.pricing.estZoneMax * zones || 1
  let path = ''
  for (let k = 0; k < N; k++) {
    const min = 300 + (900 * k) / (N - 1)
    const dd = new Date(baseDate)
    dd.setHours(Math.floor(min / 60), Math.floor(min % 60), 0, 0)
    const f = congestionFactor(dd)
    const trip = estimatedZonePrice(corridor, f) * zones
    const x = (k / (N - 1)) * 300
    const y = 58 - (Math.min(trip, maxTrip) / maxTrip) * 50
    path += `${k === 0 ? 'M' : 'L'}${x.toFixed(1)},${y.toFixed(1)} `
  }
  return { path: path.trim(), area: `${path}L300,62 L0,62 Z`.trim() }
}

export interface CorridorChipVM {
  id: string
  badge: string
  name: string
  color: string
  chipLabel: string // map marker: "$2.50" | "free"
  browsePriceLabel: string // browse row: "from $2.50" | "free now"
  hasLive: boolean
  tolledNow: boolean
  selected: boolean
}

/** Per-corridor chip + browse-row data (color, price, live/estimate, selection). */
export function buildCorridorChips(
  corridors: Corridor[],
  live: LiveResponse,
  factor: number,
  date: Date,
  selectedId: string,
): CorridorChipVM[] {
  return corridors.map((cc) => {
    const tolledNow = tollingStatus(cc, date).tolled
    const dir0 = resolveDirection(cc.directions[0], live)
    const hasLive = dir0.liveMap != null
    const ex = Math.min(3, dir0.points.length - 1)
    const fare = computeFare(cc, { id: dir0.id, points: dir0.points }, 0, ex, 'solo', { factor, live: dir0.liveMap })
    const color = !tolledNow ? C.idle : hasLive ? C.green : C.amber
    return {
      id: cc.id,
      badge: cc.routeBadge,
      name: cc.name,
      color,
      chipLabel: tolledNow ? money(fare.netToll) : 'free',
      browsePriceLabel: tolledNow ? `from ${money(fare.netToll)}` : 'free now',
      hasLive,
      tolledNow,
      selected: cc.id === selectedId,
    }
  })
}

/** Top-bar live-feed pill state for the selected corridor's fare. `live` drives
 *  the pulsing dot — true ONLY for a genuine live feed, never for sample/demo
 *  data (which would overstate it as real-time). */
export function feedPill(fare: FareBreakdown, tolled: boolean): { label: string; color: string; live: boolean } {
  if (tolled && fare.source === 'live') return { label: 'Live · 511', color: C.green, live: true }
  if (tolled && fare.source === 'sample') return { label: 'Sample · 511', color: C.green, live: false }
  if (tolled) return { label: 'Estimate', color: C.amberDeep, live: false }
  return { label: 'Off-hours', color: C.ink3, live: false }
}

/**
 * Pick the corridor direction (NB/SB/EB/WB) that matches the trip's travel vector.
 * Direction ids ARE compass headings, so we snap the dominant travel axis to the
 * available direction. `dLng`/`dLat` are the entry→exit deltas of the matched lane
 * (or the whole trip as a fallback). Used to auto-set the direction tab from a plan
 * instead of always defaulting to `directions[0]`.
 */
export function pickTravelDirection(dirIds: string[], dLng: number, dLat: number): string {
  const has = (x: string) => dirIds.includes(x)
  const ns = dLat >= 0 ? 'NB' : 'SB'
  const ew = dLng >= 0 ? 'EB' : 'WB'
  const nsAvail = has('NB') || has('SB')
  const ewAvail = has('EB') || has('WB')
  // Prefer the dominant axis of travel, but only choose a direction the corridor has.
  if (Math.abs(dLat) >= Math.abs(dLng)) {
    if (nsAvail && has(ns)) return ns
    if (ewAvail && has(ew)) return ew
  } else {
    if (ewAvail && has(ew)) return ew
    if (nsAvail && has(ns)) return ns
  }
  return dirIds[0] ?? 'NB'
}

export interface TimeSavingsVM {
  /** "~4 min faster" or "" when under a minute / not tolling. */
  label: string
  minutes: number
  /** Express-lane miles on the route — MEASURED (from the OSRM geometry), not modeled. */
  miles: number
  /** Modeled speeds at the selected time-of-day congestion intensity. */
  generalMph: number
  expressMph: number
  /** Modeled travel time (min) over `miles` in each lane class. */
  generalMin: number
  expressMin: number
  /** Express bar width as a % of the general bar (always ≤100, min 8 for visibility). */
  expressPct: number
}

/**
 * View-model for the time-saved visual. `miles` is the real measured express-lane
 * distance; the speeds (and therefore the minutes) are MODELED from the same
 * time-of-day congestion intensity `factor` that drives the toll prices — there is
 * no keyless live travel-time feed (see timeSavings.ts). Provenance is surfaced in
 * the UI so measured and modeled numbers are never conflated.
 */
export function buildTimeSavings(factor: number, miles: number): TimeSavingsVM {
  const minutes = minutesSaved(factor, miles)
  const gmph = generalSpeedMph(factor)
  const emph = expressSpeedMph(factor)
  const gMin = miles > 0 ? (60 * miles) / gmph : 0
  const eMin = miles > 0 ? (60 * miles) / emph : 0
  return {
    label: savedLabel(minutes),
    minutes: Math.round(minutes),
    miles: Math.round(miles * 10) / 10,
    generalMph: Math.round(gmph),
    expressMph: Math.round(emph),
    generalMin: Math.round(gMin),
    expressMin: Math.round(eMin),
    expressPct: gMin > 0 ? Math.max(8, Math.round((eMin / gMin) * 100)) : 100,
  }
}
