import { corridorById, corridors } from '../data/corridors'
import { computeFare, congestionFactor, estimatedZonePrice, occupancyMultiplier, tollingStatus } from './pricing'
import type { LiveZoneMap } from './pricing'

interface Check {
  name: string
  pass: boolean
  detail?: string
}

function approx(a: number, b: number, eps = 0.001) {
  return Math.abs(a - b) <= eps
}

/**
 * Runs deterministic assertions against the fare engine and dataset, logging
 * results to the console so an E2E run can read ground truth (not pixels).
 */
export function runSelfTest(): { passed: number; total: number; checks: Check[] } {
  const checks: Check[] = []
  const ok = (name: string, pass: boolean, detail?: string) => checks.push({ name, pass, detail })

  const i880 = corridorById('i880')!
  const i580 = corridorById('i580-tri-valley')!
  const i80 = corridorById('i80-solano')!
  const sr237 = corridorById('sr237-silicon-valley')!

  // Occupancy multipliers
  ok('i880 solo = full (1.0)', occupancyMultiplier(i880, 'solo') === 1)
  ok('i880 two = half (0.5)', occupancyMultiplier(i880, 'two') === 0.5)
  ok('i880 3+ = free (0)', occupancyMultiplier(i880, 'threePlus') === 0)
  ok('i580 two = free (0)', occupancyMultiplier(i580, 'two') === 0)

  // Live fare: I-880 NB 5 zones [0.75,0.75,0.75,1,1], full trip
  const nb = i880.directions.find((d) => d.id === 'NB')!
  const liveMap: LiveZoneMap = {
    0: { price: 0.75, lastUpdated: '2025-12-31T11:57:14-08:00', source: 'live' },
    1: { price: 0.75, lastUpdated: '2025-12-31T11:57:14-08:00', source: 'live' },
    2: { price: 0.75, lastUpdated: '2025-12-31T11:57:14-08:00', source: 'live' },
    3: { price: 1.0, lastUpdated: '2025-12-31T11:57:14-08:00', source: 'live' },
    4: { price: 1.0, lastUpdated: '2025-12-31T11:57:14-08:00', source: 'live' },
  }
  const full = computeFare(i880, nb, 0, nb.points.length - 1, 'solo', { factor: 0.5, live: liveMap })
  ok('i880 NB full-trip gross = 4.25', approx(full.grossToll, 4.25), `got ${full.grossToll}`)
  ok('i880 NB full-trip source = live', full.source === 'live', full.source)
  const half = computeFare(i880, nb, 0, nb.points.length - 1, 'two', { factor: 0.5, live: liveMap })
  ok('i880 NB 2-person net = 2.13', approx(half.netToll, 2.13), `got ${half.netToll}`)
  const free = computeFare(i880, nb, 0, nb.points.length - 1, 'threePlus', { factor: 0.5, live: liveMap })
  ok('i880 NB 3+ net = 0', free.netToll === 0 && !!free.freeReason)

  // Partial live trip: zones 0..2 (two zones) = 1.50
  const partial = computeFare(i880, nb, 0, 2, 'solo', { factor: 0, live: liveMap })
  ok('i880 NB entry0->exit2 gross = 1.50', approx(partial.grossToll, 1.5), `got ${partial.grossToll}`)

  // Estimator monotonic in congestion + respects min
  const low = estimatedZonePrice(i80, congestionFactor(new Date('2026-06-14T03:00:00')))
  const high = estimatedZonePrice(i80, congestionFactor(new Date('2026-06-17T08:00:00')))
  ok('i80 estimate rises with congestion', high >= low, `low=${low} high=${high}`)
  ok('i80 estimate >= $0.75 min', estimatedZonePrice(i80, 0) >= 0.75)
  ok('sr237 estimate within [min,max]', (() => {
    const p = estimatedZonePrice(sr237, 1)
    return p >= 0.3 && p <= 5.6
  })())

  // Tolling windows
  ok('i580 not tolled Sunday', tollingStatus(i580, new Date('2026-06-14T08:00:00')).tolled === false)
  ok('i80 tolled Sunday (daily)', tollingStatus(i80, new Date('2026-06-14T08:00:00')).tolled === true)
  ok('i580 not tolled at 21:00', tollingStatus(i580, new Date('2026-06-17T21:00:00')).tolled === false)
  ok('i580 tolled at 08:00 weekday', tollingStatus(i580, new Date('2026-06-17T08:00:00')).tolled === true)

  // Dataset integrity
  ok('8 corridors loaded', corridors.length === 8, `got ${corridors.length}`)
  ok('every corridor has >=1 direction with >=2 points', corridors.every((c) => c.directions.every((d) => d.points.length >= 2)))
  ok('every corridor has sources', corridors.every((c) => c.sources.length > 0))

  const passed = checks.filter((c) => c.pass).length
  const total = checks.length

  for (const c of checks) {
    if (c.pass) console.log(`%c[selftest] PASS%c ${c.name}`, 'color:#1c7a52;font-weight:600', 'color:inherit')
    else console.error(`[selftest] FAIL ${c.name}${c.detail ? ' — ' + c.detail : ''}`)
  }
  console.log(`SELFTEST: ${passed}/${total} passed`)
  ;(window as unknown as { __SELFTEST__?: unknown }).__SELFTEST__ = { passed, total, checks }
  return { passed, total, checks }
}
