import type { AccessPoint, Corridor, FareBreakdown, Occupancy, RateSourceKind, ZoneRate } from './types'

/** Minimal shape the fare engine needs from a direction (live or static). */
export interface DirectionLike {
  id: string
  label?: string
  points: AccessPoint[]
}

// ---------------------------------------------------------------------------
// Pure fare engine. No globals, no Date.now() — every function takes the time
// it needs. This keeps the math deterministic and unit-testable.
//
// Unified model: a trip from entry point i to exit point j traverses zones
// i..j-1. Each zone has a price that is EITHER a live reading from the 511 feed
// OR a time-of-day estimate. Trip toll = sum(zone prices) x occupancy multiplier.
// ---------------------------------------------------------------------------

const clamp = (x: number, lo: number, hi: number) => Math.min(hi, Math.max(lo, x))
const gaussian = (x: number, mu: number, sd: number) => Math.exp(-0.5 * ((x - mu) / sd) ** 2)
const round = (x: number, step: number) => Math.round(x / step) * step

/** Day-of-week + time-of-day congestion intensity in [0,1]. */
export function congestionFactor(date: Date): number {
  const dow = date.getDay() // 0 Sun .. 6 Sat
  const min = date.getHours() * 60 + date.getMinutes()
  const am = gaussian(min, 8 * 60, 75) // morning peak ~8:00
  const pm = gaussian(min, 17 * 60 + 30, 90) // evening peak ~5:30p
  const midday = 0.28 * gaussian(min, 12 * 60 + 30, 150)
  let f = 0.12 + 0.88 * Math.max(am, pm, midday)
  if (dow === 0 || dow === 6) f *= 0.5 // lighter on weekends
  return clamp(f, 0, 1)
}

export interface TollingStatus {
  tolled: boolean
  reason: string
}

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

/** Whether a corridor is actively tolling at the given local time. */
export function tollingStatus(corridor: Corridor, date: Date): TollingStatus {
  const dow = date.getDay()
  const min = date.getHours() * 60 + date.getMinutes()
  const [sh, sm] = corridor.hours.start.split(':').map(Number)
  const [eh, em] = corridor.hours.end.split(':').map(Number)
  const start = sh * 60 + sm
  const end = eh * 60 + em
  const weekday = dow >= 1 && dow <= 5
  const dayOk = corridor.hours.days === 'Daily' || weekday
  const timeOk = min >= start && min < end
  if (!dayOk) {
    return { tolled: false, reason: `Open to all — free on ${DAY_NAMES[dow]} (tolled ${corridor.hours.days})` }
  }
  if (!timeOk) {
    return { tolled: false, reason: `Open to all — free outside ${corridor.hours.start}–${corridor.hours.end}` }
  }
  return { tolled: true, reason: `Tolled now (${corridor.hours.start}–${corridor.hours.end}, ${corridor.hours.days})` }
}

/** Estimated price for a single zone, given congestion intensity. */
export function estimatedZonePrice(corridor: Corridor, factor: number): number {
  const { estZoneMin, estZoneMax, minZoneToll } = corridor.pricing
  const raw = estZoneMin + clamp(factor, 0, 1) * (estZoneMax - estZoneMin)
  const rounded = round(raw, 0.25)
  return Math.max(rounded, minZoneToll ?? estZoneMin)
}

/** Multiplier applied to the gross toll for the chosen occupancy. */
export function occupancyMultiplier(corridor: Corridor, occ: Occupancy): number {
  if (occ === 'threePlus') return 0
  if (occ === 'two') return corridor.twoPersonRule === 'free' ? 0 : 0.5
  return 1
}

function freeReason(corridor: Corridor, occ: Occupancy): string | undefined {
  if (occ === 'threePlus') return '3+ carpool, motorcycle, vanpool or transit — free with FasTrak Flex set to 3'
  if (occ === 'two' && corridor.twoPersonRule === 'free')
    return `2-person carpool — free on ${corridor.route} with FasTrak Flex set to 2`
  return undefined
}

/** Live price for one zone, keyed by zone index, as normalized by the server. */
export interface LiveZone {
  price: number
  lastUpdated: string | null
  source: Extract<RateSourceKind, 'live' | 'sample'>
}
export type LiveZoneMap = Record<number, LiveZone>

export interface FareOptions {
  /** Congestion factor for the estimate path, from `congestionFactor`. */
  factor: number
  /** Live per-zone prices, when available. */
  live?: LiveZoneMap | null
}

/** Build the per-zone rate list for zones entryIdx..exitIdx-1. */
export function buildZoneRates(
  corridor: Corridor,
  direction: DirectionLike,
  entryIdx: number,
  exitIdx: number,
  opts: FareOptions,
): ZoneRate[] {
  const lo = Math.min(entryIdx, exitIdx)
  const hi = Math.max(entryIdx, exitIdx)
  const rates: ZoneRate[] = []
  for (let i = lo; i < hi; i++) {
    const fromLabel = direction.points[i]?.label ?? `Point ${i}`
    const toLabel = direction.points[i + 1]?.label ?? `Point ${i + 1}`
    const liveZone = opts.live ? opts.live[i] : undefined
    if (liveZone) {
      rates.push({ index: i, fromLabel, toLabel, price: liveZone.price, source: liveZone.source, lastUpdated: liveZone.lastUpdated })
    } else {
      rates.push({ index: i, fromLabel, toLabel, price: estimatedZonePrice(corridor, opts.factor), source: 'estimate', lastUpdated: null })
    }
  }
  return rates
}

function overallSource(rates: ZoneRate[]): RateSourceKind {
  if (rates.length === 0) return 'estimate'
  if (rates.every((r) => r.source === 'live')) return 'live'
  if (rates.every((r) => r.source === 'sample')) return 'sample'
  if (rates.every((r) => r.source === 'live' || r.source === 'sample')) return 'sample'
  return 'estimate'
}

/** Compute the full fare breakdown for a trip. */
export function computeFare(
  corridor: Corridor,
  direction: DirectionLike,
  entryIdx: number,
  exitIdx: number,
  occupancy: Occupancy,
  opts: FareOptions,
): FareBreakdown {
  const zones = buildZoneRates(corridor, direction, entryIdx, exitIdx, opts)
  const grossToll = round(zones.reduce((s, z) => s + z.price, 0), 0.01)
  const occupancyMultiplier_ = occupancyMultiplier(corridor, occupancy)
  const netToll = round(grossToll * occupancyMultiplier_, 0.01)
  const lastUpdates = zones.map((z) => z.lastUpdated).filter((x): x is string => !!x).sort()
  return {
    corridorId: corridor.id,
    directionId: direction.id,
    occupancy,
    zones,
    grossToll,
    occupancyMultiplier: occupancyMultiplier_,
    netToll,
    source: overallSource(zones),
    asOf: lastUpdates.length ? lastUpdates[lastUpdates.length - 1] : null,
    freeReason: occupancyMultiplier_ === 0 ? freeReason(corridor, occupancy) : undefined,
  }
}

/** Format cents to a $-string with two decimals. */
export function money(n: number): string {
  return `$${n.toFixed(2)}`
}
