// Modeled express-lane time savings vs the general-purpose (GP) lanes.
//
// There is NO keyless live or historical travel-time feed for these corridors:
// Caltrans PeMS requires an account and disallows programmatic access; the 511
// travel-times API needs a token and this app's 511 feed is frozen (Dec 2025);
// OSRM gives free-flow distance only, no traffic. So time saved is MODELED from
// the same time-of-day congestion intensity `f` used for pricing, calibrated to
// published agency performance figures — NOT measured. Always label it as an
// estimate.
//
// Calibration (sources in the corridor fact sheets / MTC quarterly reports):
//  • Bay Area express lanes are speed-managed to a ≥45 mph floor.
//  • GP lanes drop to ~20–40 mph at peak (use the congested low end a driver feels).
//  • VTA advertises SR-237 (~4 mi) saves 5–20 min at peak; our model → ~7 min @ f=1.
//  • MTC reports I-680 express ~9–17 mph faster than GP at peak bottlenecks.

const clamp = (x: number, lo: number, hi: number) => Math.min(hi, Math.max(lo, x))

/** Express-lane speed (mph) at congestion intensity f∈[0,1]. Held near the 45 mph floor. */
export function expressSpeedMph(f: number): number {
  return Math.max(45, 65 - 17 * clamp(f, 0, 1))
}

/** General-purpose lane speed (mph) at congestion intensity f∈[0,1]. */
export function generalSpeedMph(f: number): number {
  return Math.max(12, 65 - 45 * clamp(f, 0, 1))
}

/** Modeled minutes saved by the express lane over `miles` at congestion intensity f. */
export function minutesSaved(f: number, miles: number): number {
  if (miles <= 0) return 0
  const saved = 60 * miles * (1 / generalSpeedMph(f) - 1 / expressSpeedMph(f))
  return Math.max(0, saved)
}

const M_PER_DEG_LAT = 111_320
const MILES_PER_M = 1 / 1609.344

/** Length of a [lng,lat] polyline in miles (equirectangular — fine at Bay Area scale). */
export function pathMiles(coords: [number, number][]): number {
  if (!coords || coords.length < 2) return 0
  let m = 0
  for (let i = 1; i < coords.length; i++) {
    const lat = ((coords[i][1] + coords[i - 1][1]) / 2) * (Math.PI / 180)
    const dx = (coords[i][0] - coords[i - 1][0]) * 111_320 * Math.cos(lat)
    const dy = (coords[i][1] - coords[i - 1][1]) * M_PER_DEG_LAT
    m += Math.hypot(dx, dy)
  }
  return m * MILES_PER_M
}

/** Human label, e.g. "~12 min faster" or "" when the saving is under a minute. */
export function savedLabel(minutes: number): string {
  const r = Math.round(minutes)
  return r >= 1 ? `~${r} min faster` : ''
}
