// Driving route between two points via the public OSRM demo server (keyless).
import type { GeoResult } from './geocode'
import { TtlCache, createDeduper } from './cache'

export interface RouteResult {
  coords: [number, number][] // [lng, lat] following the road network
  distanceM: number
  durationS: number
}

// Routes are stable (road network), so cache generously. A cached `null` means
// "we asked and there is no driving route" — also worth not re-asking.
const routeCache = new TtlCache<RouteResult | null>(60, 30 * 60_000)
const dedupeRoute = createDeduper(routeCache)

/** Cache key from coordinates rounded to ~1 m, so trivially-different endpoints reuse a route. */
function routeKey(a: GeoResult, b: GeoResult): string {
  return `${a.lng.toFixed(5)},${a.lat.toFixed(5)};${b.lng.toFixed(5)},${b.lat.toFixed(5)}`
}

export async function fetchRoute(a: GeoResult, b: GeoResult, signal?: AbortSignal): Promise<RouteResult | null> {
  const url = `https://router.project-osrm.org/route/v1/driving/${a.lng},${a.lat};${b.lng},${b.lat}?overview=full&geometries=geojson`
  try {
    return await dedupeRoute(routeKey(a, b), async () => {
      const res = await fetch(url, { signal })
      // Throw (not return null) on transient HTTP failure so it is NOT cached.
      if (!res.ok) throw new Error(`route http ${res.status}`)
      const j = (await res.json()) as { code?: string; routes?: { geometry?: { coordinates?: [number, number][] }; distance?: number; duration?: number }[] }
      const r = j?.routes?.[0]
      if (j.code !== 'Ok' || !r?.geometry?.coordinates || r.geometry.coordinates.length < 2) return null
      return { coords: r.geometry.coordinates, distanceM: r.distance ?? 0, durationS: r.duration ?? 0 }
    })
  } catch {
    // AbortError or thrown HTTP error — surfaced as "no route", not cached.
    return null
  }
}
