import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import type { FocusEvent } from 'react'
import { corridorById, corridors } from './data/corridors'
import { computeFare, congestionFactor, money, tollingStatus } from './lib/pricing'
import type { Occupancy } from './lib/types'
import { EMPTY_LIVE, fetchLive, resolveDirection } from './lib/liveClient'
import type { LiveResponse } from './lib/liveClient'
import { runSelfTest } from './lib/selftest'
import {
  buildCorridorChips,
  buildDepartureCurve,
  buildOccOptions,
  buildReadout,
  buildStops,
  buildTimeSavings,
  buildTripReadout,
  feedPill,
  occupancyRuleHint,
  pickTravelDirection,
} from './lib/flexView'
import { readTripFromUrl, tripToQuery } from './lib/urlState'
import { BRIDGES } from './data/bridges'
import { geoAnchors } from './data/geo'
import { searchAddresses } from './lib/geocode'
import type { GeoResult } from './lib/geocode'
import { fetchRoute } from './lib/route'
import type { RouteResult } from './lib/route'
import { matchLanes } from './lib/matchLanes'
import type { LaneMatch } from './lib/matchLanes'
import { pathMiles } from './lib/timeSavings'
import { fetchTraffic, nearAny } from './lib/traffic'
import type { TrafficItem } from './lib/traffic'
import { FlexMap, corridorCoords } from './components/FlexMap'
import type { BridgePin } from './components/FlexMap'
import { TopBar } from './components/TopBar'
import { PlanPanel } from './components/PlanPanel'
import styles from './App.module.css'

type TimeMode = 'now' | 'custom'
interface TimeValue {
  mode: TimeMode
  minutes: number
  weekend: boolean
}
interface Plan {
  start: GeoResult
  end: GeoResult
  route: RouteResult
  matches: LaneMatch[]
}

const initial = readTripFromUrl()
const clamp = (x: number, lo: number, hi: number) => Math.min(hi, Math.max(lo, x))

// Bridge pin baseline when no live posted price is available (standard 2025
// Bay Area passenger tolls; Golden Gate is the lone outlier). Clearly labeled
// "typical" in the pin tooltip so it never reads as a live posted price.
const BRIDGE_BASE: Record<string, number> = { 'Golden Gate': 9.75 }
// Stable empty reference so a no-trip render doesn't churn FlexMap's re-sync memo.
const EMPTY_SPANS: [number, number][][] = []
const normBridge = (s: string) => s.toLowerCase().replace(/\s*bridge\s*$/, '').trim()

function effectiveDate(time: TimeValue, now: Date): Date {
  if (time.mode === 'now') return now
  const d = new Date(now)
  const targetDow = time.weekend ? 6 : 3
  d.setDate(d.getDate() + (targetDow - d.getDay()))
  d.setHours(Math.floor(time.minutes / 60), time.minutes % 60, 0, 0)
  return d
}

function nearestCorridor(from: { lng: number; lat: number }, to: { lng: number; lat: number }) {
  const mid = { lng: (from.lng + to.lng) / 2, lat: (from.lat + to.lat) / 2 }
  let best = corridors[0]
  let bd = Infinity
  for (const cc of corridors) {
    const coords = corridorCoords(cc.id)
    let dmin = Infinity
    for (let i = 0; i < coords.length; i += 8) {
      const d = Math.hypot(coords[i][0] - mid.lng, coords[i][1] - mid.lat)
      if (d < dmin) dmin = d
    }
    if (dmin < bd) {
      bd = dmin
      best = cc
    }
  }
  return best
}

export function App() {
  const [selectedId, setSelectedId] = useState(() => (initial.corridor && corridorById(initial.corridor) ? initial.corridor : 'i880'))
  const [directionId, setDirectionId] = useState(initial.dir ?? 'NB')
  const [entry, setEntry] = useState(initial.entry ?? 0)
  const [exit, setExit] = useState(initial.exit ?? 3)
  const [occupancy, setOccupancy] = useState<Occupancy>(initial.occupancy ?? 'solo')
  const [time, setTime] = useState<TimeValue>(
    initial.timeMode === 'custom'
      ? { mode: 'custom', minutes: initial.minutes ?? 8 * 60, weekend: initial.weekend ?? false }
      : { mode: 'now', minutes: 8 * 60, weekend: initial.weekend ?? false },
  )
  const [now, setNowTime] = useState(() => new Date())
  const [live, setLive] = useState<LiveResponse>(EMPTY_LIVE)
  const [lastFetched, setLastFetched] = useState<Date | null>(null)
  const [traffic, setTraffic] = useState<TrafficItem[]>([])
  const [copied, setCopied] = useState(false)
  const [theme, setTheme] = useState<'dark' | 'light'>('dark')
  const [browseOpen, setBrowseOpen] = useState(false)
  const [bridgesOn, setBridgesOn] = useState(true)

  // Plan-by-address (city/anchor matching → nearest express lane).
  const [fromText, setFromText] = useState('')
  const [toText, setToText] = useState('')
  const [focusField, setFocusField] = useState<'from' | 'to' | null>(null)
  const [plan, setPlan] = useState<Plan | null>(null)
  const [addrResults, setAddrResults] = useState<GeoResult[]>([])
  const fromPlace = useRef<GeoResult | null>(null)
  const toPlace = useRef<GeoResult | null>(null)
  // Monotonic token so a slow route fetch that lands after the plan changed is ignored.
  const routeReq = useRef(0)

  // ── live feed: fetch on mount, poll every 90s, manual refresh ──
  const refresh = useCallback(() => {
    const ctrl = new AbortController()
    fetchLive(ctrl.signal).then((l) => {
      setLive(l)
      setLastFetched(new Date())
    })
    return () => ctrl.abort()
  }, [])

  useEffect(() => {
    runSelfTest()
    const stop = refresh()
    const id = window.setInterval(refresh, 90_000)
    return () => {
      stop()
      window.clearInterval(id)
    }
  }, [refresh])

  // Keep "now" fresh for the congestion estimate.
  useEffect(() => {
    const t = window.setInterval(() => setNowTime(new Date()), 60_000)
    return () => window.clearInterval(t)
  }, [])

  // ── live 511 traffic (incidents + work zones): the one genuinely-live feed.
  // Fetch on mount, poll every 3 min (server caches; keeps us under the rate limit). ──
  const refreshTraffic = useCallback(() => {
    const ctrl = new AbortController()
    fetchTraffic(ctrl.signal).then((r) => {
      if (r.source === 'live' || r.source === 'sample') setTraffic(r.items)
    })
    return () => ctrl.abort()
  }, [])
  useEffect(() => {
    const stop = refreshTraffic()
    const id = window.setInterval(refreshTraffic, 180_000)
    return () => {
      stop()
      window.clearInterval(id)
    }
  }, [refreshTraffic])

  // Debounced address geocoding (Photon/OSM, keyless). Aborts the in-flight request
  // when the query changes; short queries fall back to the city anchors (no fetch).
  useEffect(() => {
    if (!focusField) return
    const q = (focusField === 'from' ? fromText : toText).trim()
    if (q.length < 3) {
      setAddrResults([])
      return
    }
    const ctrl = new AbortController()
    const t = window.setTimeout(() => {
      searchAddresses(q, ctrl.signal).then((r) => setAddrResults(r))
    }, 250)
    return () => {
      window.clearTimeout(t)
      ctrl.abort()
    }
  }, [focusField, fromText, toText])

  // ── derived model ──
  const corridor = corridorById(selectedId) ?? corridors[0]
  const direction = corridor.directions.find((d) => d.id === directionId) ?? corridor.directions[0]
  const activeDir = useMemo(() => resolveDirection(direction, live), [direction, live])
  // Memoized so its object identity is stable across unrelated re-renders —
  // otherwise the chips memo (and the map's bridge markers) churn every render.
  const date = useMemo(() => effectiveDate(time, now), [time, now])
  const factor = congestionFactor(date)
  const tolled = tollingStatus(corridor, date)
  const lastIdx = activeDir.points.length - 1
  const safeEntry = Math.max(0, Math.min(entry, lastIdx - 1))
  const safeExit = Math.min(Math.max(exit, safeEntry + 1), lastIdx)
  const effMinutes = time.mode === 'now' ? now.getHours() * 60 + now.getMinutes() : time.minutes
  const effWeekend = time.mode === 'now' ? now.getDay() === 0 || now.getDay() === 6 : time.weekend

  const fare = useMemo(
    () => computeFare(corridor, { id: activeDir.id, points: activeDir.points }, safeEntry, safeExit, occupancy, { factor, live: activeDir.liveMap }),
    [corridor, activeDir, safeEntry, safeExit, occupancy, factor],
  )

  // Clamp the trip to the active (possibly live-swapped) point count.
  useEffect(() => {
    setEntry((e) => clamp(e, 0, Math.max(0, lastIdx - 1)))
    setExit((x) => clamp(x, 1, lastIdx))
  }, [lastIdx])

  // ── view models ──
  const tripMode = plan != null
  const readout = plan ? buildTripReadout(plan.matches, occupancy, date) : buildReadout(fare, tolled, occupancy)
  const occWord = occupancy === 'solo' ? 'solo' : occupancy === 'two' ? '2 people' : '3 plus'
  const announce = `${tripMode ? '' : corridor.routeBadge + ' '}${readout.readoutLabel}: ${readout.priceText}${readout.isFree ? '' : `, ${occWord}`}`
  const stops = buildStops(activeDir.points, safeEntry, safeExit)
  const occOptions = buildOccOptions(corridor, occupancy)
  const ruleHint = occupancyRuleHint(corridor)
  const curve = buildDepartureCurve(corridor, safeExit - safeEntry, date)
  const markerLeft = `${(((clamp(effMinutes, 300, 1200) - 300) / 900) * 100).toFixed(1)}%`
  const chips = useMemo(() => buildCorridorChips(corridors, live, factor, date, selectedId), [live, factor, date, selectedId])
  const pill = feedPill(fare, tolled.tolled)

  // Modeled express-lane miles → time saved vs the general-purpose lanes (no live
  // travel-time feed is keyless, so this is modeled from `factor`; see timeSavings.ts).
  const denom = Math.max(1, lastIdx)
  // Only TOLLED express miles count toward the modeled time-saved — a corridor that's
  // free at the chosen time has no express benefit, so its miles must not inflate it.
  const savingsMiles = plan
    ? plan.matches.filter((m) => tollingStatus(corridorById(m.corridorId) ?? corridor, date).tolled).reduce((s, m) => s + pathMiles(m.span), 0)
    : tolled.tolled
      ? pathMiles(corridorCoords(selectedId)) * ((safeExit - safeEntry) / denom)
      : 0
  const timeSaved = buildTimeSavings(factor, savingsMiles)
  const routeCoords = plan ? (plan.route.coords as [number, number][]) : null
  // Memoized so an unrelated re-render (60s tick, keystroke) doesn't churn the map's
  // bridge markers via FlexMap's matchSpans-dependent re-sync effect.
  const matchSpans = useMemo(() => (plan ? plan.matches.map((m) => m.span) : EMPTY_SPANS), [plan])

  // Live traffic relevant to what the user is viewing: incidents/work-zones within
  // ~2.5 mi of the planned route (trip mode) or the selected corridor (single mode).
  const trafficPolylines = useMemo<[number, number][][]>(
    () => (plan ? [plan.route.coords as [number, number][]] : [corridorCoords(selectedId)]),
    [plan, selectedId],
  )
  const relevantTraffic = useMemo(() => nearAny(traffic, trafficPolylines, 4000), [traffic, trafficPolylines])

  const bridges: BridgePin[] = useMemo(() => {
    return BRIDGES.map((b) => {
      const lng = (b.p1[0] + b.p2[0]) / 2
      const lat = (b.p1[1] + b.p2[1]) / 2
      const feed = live.bridges?.find((x) => normBridge(x.name) === normBridge(b.name))
      const price = feed?.price ?? null
      const base = BRIDGE_BASE[b.name] ?? 8
      // A leading "~" marks a typical baseline (no live posted price) so a pin is
      // never mistaken for a real gantry reading.
      return { name: b.name, lng, lat, tollLabel: price != null ? money(price) : `~${money(base)}`, live: price != null }
    })
  }, [live.bridges])

  // Address autocomplete: real geocoding (Photon/OSM) for >=3 chars; the curated
  // city anchors for short queries. The fetch itself is debounced + abortable below.
  const query = (focusField === 'from' ? fromText : focusField === 'to' ? toText : '').trim()
  const placeList: GeoResult[] = !focusField
    ? []
    : query.length >= 3
      ? addrResults
      : geoAnchors.filter((a) => a.label.toLowerCase().includes(query.toLowerCase())).map((a) => ({ label: a.label, lng: a.lng, lat: a.lat }))

  const fracDenom = Math.max(1, lastIdx)

  // ── actions ──
  const selectCorridor = useCallback((id: string) => {
    const c = corridorById(id)
    if (!c) return
    const dir = c.directions[0]
    routeReq.current++
    setPlan(null) // picking a corridor exits address-trip mode
    setSelectedId(id)
    setDirectionId(dir.id)
    setEntry(0)
    setExit(Math.min(3, dir.points.length - 1))
    setBrowseOpen(false)
  }, [])

  const setDirection = useCallback(
    (id: string) => {
      const dir = corridor.directions.find((d) => d.id === id) ?? corridor.directions[0]
      setDirectionId(id)
      setEntry(0)
      setExit(Math.min(3, dir.points.length - 1))
    },
    [corridor],
  )

  const pickStop = useCallback(
    (i: number) => {
      let e = safeEntry
      let x = safeExit
      if (Math.abs(i - safeEntry) <= Math.abs(i - safeExit)) e = Math.min(i, safeExit - 1)
      else x = Math.max(i, safeEntry + 1)
      e = clamp(e, 0, lastIdx - 1)
      x = clamp(x, e + 1, lastIdx)
      setEntry(e)
      setExit(x)
    },
    [safeEntry, safeExit, lastIdx],
  )

  // Fetch the driving route for the picked endpoints and map-match it to express
  // lanes. A monotonic token ignores a slow fetch that lands after the plan changed.
  const runPlan = useCallback(
    (from: GeoResult, to: GeoResult) => {
      const reqId = ++routeReq.current
      fetchRoute(from, to).then((route) => {
        if (reqId !== routeReq.current) return // superseded by a newer plan/clear
        const dirIdsOf = (c: { directions: { id: string }[] }) => c.directions.map((d) => d.id)
        if (!route) {
          setPlan(null)
          const best = nearestCorridor(from, to)
          setSelectedId(best.id)
          // No road geometry — infer direction from the straight-line trip vector.
          setDirectionId(pickTravelDirection(dirIdsOf(best), to.lng - from.lng, to.lat - from.lat))
          return
        }
        const matches = matchLanes(route.coords)
        setPlan({ start: from, end: to, route, matches })
        const primary = matches.slice().sort((a, b) => b.zones - a.zones)[0]
        const best = primary?.corridorId ?? nearestCorridor(from, to).id
        const c = corridorById(best)
        setSelectedId(best)
        if (c) {
          // Auto-select the direction that matches the way the route actually travels
          // along the primary matched lane (span[0]→span[last], respecting `forward`).
          let dLng = to.lng - from.lng
          let dLat = to.lat - from.lat
          if (primary && primary.span.length >= 2) {
            const sp = primary.span
            const a = primary.forward ? sp[0] : sp[sp.length - 1]
            const b = primary.forward ? sp[sp.length - 1] : sp[0]
            dLng = b[0] - a[0]
            dLat = b[1] - a[1]
          }
          setDirectionId(pickTravelDirection(dirIdsOf(c), dLng, dLat))
        }
      })
    },
    [],
  )

  const pickPlace = useCallback(
    (field: 'from' | 'to', place: GeoResult) => {
      if (field === 'from') {
        fromPlace.current = place
        setFromText(place.label)
      } else {
        toPlace.current = place
        setToText(place.label)
      }
      setFocusField(null)
      setAddrResults([])
      if (fromPlace.current && toPlace.current) runPlan(fromPlace.current, toPlace.current)
    },
    [runPlan],
  )

  const swapEnds = useCallback(() => {
    const f = fromPlace.current
    const t = toPlace.current
    fromPlace.current = t
    toPlace.current = f
    setFromText(toText)
    setToText(fromText)
    if (fromPlace.current && toPlace.current) runPlan(fromPlace.current, toPlace.current)
  }, [fromText, toText, runPlan])

  const clearTrip = useCallback(() => {
    routeReq.current++
    fromPlace.current = null
    toPlace.current = null
    setPlan(null)
    setFromText('')
    setToText('')
    setFocusField(null)
    setAddrResults([])
  }, [])

  const onCopyLink = useCallback(() => {
    const url = `${window.location.origin}${window.location.pathname}${window.location.search}`
    navigator.clipboard?.writeText(url).then(
      () => {
        setCopied(true)
        window.setTimeout(() => setCopied(false), 1600)
      },
      () => {},
    )
  }, [])

  const toggleTheme = useCallback(() => setTheme((t) => (t === 'dark' ? 'light' : 'dark')), [])

  // Collapse the suggestion list only when focus leaves the whole search group.
  // Tabbing input → swap → a suggestion keeps relatedTarget inside the group, so
  // keyboard/SR users can actually reach the options (WCAG 2.1.1).
  const onSearchBlur = useCallback((e: FocusEvent<HTMLDivElement>) => {
    if (!e.currentTarget.contains(e.relatedTarget as Node | null)) setFocusField(null)
  }, [])

  // ── URL deep-link sync (shareable trip state) ──
  const query0 = useMemo(
    () =>
      tripToQuery({
        corridor: selectedId,
        dir: activeDir.id,
        entry: safeEntry,
        exit: safeExit,
        occupancy,
        timeMode: time.mode === 'now' ? 'now' : 'custom',
        minutes: time.mode === 'now' ? effMinutes : time.minutes,
        weekend: effWeekend,
      }),
    [selectedId, activeDir.id, safeEntry, safeExit, occupancy, time, effMinutes, effWeekend],
  )
  useEffect(() => {
    window.history.replaceState(null, '', `${window.location.pathname}?${query0}`)
  }, [query0])

  // ── ground-truth debug hook for console-based E2E (not pixels) ──
  useEffect(() => {
    ;(window as unknown as { __BAYFLEX__?: unknown }).__BAYFLEX__ = {
      corridorId: corridor.id,
      directionId: activeDir.id,
      entry: safeEntry,
      exit: safeExit,
      occupancy,
      tolled: tolled.tolled,
      fare,
      feedStatus: fare.source,
    }
  }, [corridor.id, activeDir.id, safeEntry, safeExit, occupancy, tolled.tolled, fare])

  // ── labels ──
  const timeLabel =
    time.mode === 'now'
      ? 'now'
      : (() => {
          const h = Math.floor(effMinutes / 60)
          const mm = effMinutes % 60
          const ap = h >= 12 ? 'PM' : 'AM'
          const hh = ((h + 11) % 12) + 1
          return `${hh}:${String(mm).padStart(2, '0')} ${ap}${effWeekend ? ' Sat' : ' Wed'}`
        })()
  const updatedLabel = lastFetched
    ? `Updated ${lastFetched.toLocaleTimeString(undefined, { hour: 'numeric', minute: '2-digit', second: '2-digit' })}`
    : 'Updating…'
  const tripMatchLabel = plan
    ? plan.matches.length
      ? `Uses ${plan.matches.length} express lane${plan.matches.length === 1 ? '' : 's'} · ${(plan.route.distanceM / 1609.344).toFixed(0)} mi drive`
      : 'No express lanes on this route'
    : ''

  const suggestions = placeList.slice(0, 6).map((a) => ({ label: a.label, pick: () => pickPlace(focusField as 'from' | 'to', a) }))
  const showSuggest = !!focusField && suggestions.length > 0

  return (
    <div className={styles.app}>
      <a href="#plan" className={styles.skipLink}>
        Skip to planner
      </a>

      <FlexMap
        chips={chips}
        selectedId={selectedId}
        entryFrac={safeEntry / fracDenom}
        exitFrac={safeExit / fracDenom}
        theme={theme}
        bridgesOn={bridgesOn}
        bridges={bridges}
        routeCoords={routeCoords}
        matchSpans={matchSpans}
        traffic={relevantTraffic}
        onSelect={selectCorridor}
      />

      <TopBar
        feedLabel={pill.label}
        feedColor={pill.color}
        feedLive={pill.live}
        updatedLabel={updatedLabel}
        onRefresh={refresh}
        theme={theme}
        onToggleTheme={toggleTheme}
      />

      <PlanPanel
        fromText={fromText}
        toText={toText}
        suggestions={suggestions}
        showSuggest={showSuggest}
        onFromInput={(v) => {
          setFromText(v)
          setFocusField('from')
        }}
        onToInput={(v) => {
          setToText(v)
          setFocusField('to')
        }}
        onFromFocus={() => setFocusField('from')}
        onToFocus={() => setFocusField('to')}
        onSearchBlur={onSearchBlur}
        onCloseSuggest={() => setFocusField(null)}
        onSwap={swapEnds}
        hasTrip={!!plan}
        tripMatchLabel={tripMatchLabel}
        onClearTrip={clearTrip}
        badge={corridor.routeBadge}
        corrName={corridor.name}
        corrSub={`${corridor.operator} · ${corridor.county} County · opened ${corridor.opened}`}
        browseOpen={browseOpen}
        browseLabel={browseOpen ? 'Close ▴' : 'All ▾'}
        onToggleBrowse={() => setBrowseOpen((v) => !v)}
        chips={chips}
        onSelectCorridor={selectCorridor}
        directions={corridor.directions.map((d) => ({ id: d.id, label: d.label }))}
        directionId={directionId}
        onSetDirection={setDirection}
        readout={readout}
        announce={announce}
        tripMode={tripMode}
        timeSaved={timeSaved}
        traffic={relevantTraffic}
        stops={stops}
        onPickStop={pickStop}
        occOptions={occOptions}
        onSetOccupancy={setOccupancy}
        ruleHint={ruleHint}
        timeLabel={timeLabel}
        isNow={time.mode === 'now'}
        onSetNow={() => setTime((t) => ({ ...t, mode: 'now' }))}
        minutes={effMinutes}
        onTime={(m) => setTime({ mode: 'custom', minutes: m, weekend: effWeekend })}
        curvePath={curve.path}
        curveArea={curve.area}
        markerLeft={markerLeft}
        nowColor={time.mode === 'now' ? '#35d07a' : '#8a8576'}
        nowBg={time.mode === 'now' ? 'rgba(53,208,122,.12)' : '#14181e'}
        nowBorder={time.mode === 'now' ? 'rgba(53,208,122,.35)' : '#2c323b'}
        copyLabel={copied ? '✓ Link copied' : '⎘ Copy link'}
        onCopyLink={onCopyLink}
        bridgesOn={bridgesOn}
        onToggleBridges={() => setBridgesOn((v) => !v)}
      />

      <div className={styles.legend} aria-hidden="true">
        <div className={`${styles.legendRow} ${styles.legendLive}`}>
          <span className={`${styles.lgSwatch} ${styles.lgLive}`} /> Live price
        </div>
        <div className={`${styles.legendRow} ${styles.legendEst}`}>
          <span className={`${styles.lgSwatch} ${styles.lgEst}`} /> Estimated
        </div>
        <div className={`${styles.legendRow} ${styles.legendIdle}`}>
          <span className={`${styles.lgSwatch} ${styles.lgIdle}`} /> Off-hours
        </div>
      </div>
    </div>
  )
}
