import type { Corridor, AccessPoint } from '../lib/types'

// ---------------------------------------------------------------------------
// Canonical dataset for the greater Bay Area express ("flex") lane network.
//
// Every toll figure here is either (a) published by the operating agency and
// cited in `sources`, or (b) a clearly-labeled modeling bound used only by the
// time-of-day ESTIMATOR (pricing.estZoneMin / estZoneMax). Published minimums
// and observed peaks carry a note; modeled interior access points are marked
// `known: false`. Live corridors (I-880, I-680 Contra Costa) override their
// zones with real 511 feed data when it is fresh.
//
// Occupancy model: solo (Flex=1) always pays full; 3+ (Flex=3) is free on every
// corridor; the 2-person (Flex=2) rule differs per corridor — `twoPersonRule`
// is "free" on I-580 / I-680, "half" on I-80 / I-880 / US-101 / SR-237.
// ---------------------------------------------------------------------------

