/** Verified Bay Area tolled bridge segments with direction data. */
export interface BridgeDef {
  /** Must match the 511 feed name used in BridgeToll.name */
  name: string
  /** Segment endpoint 1 [lng, lat] */
  p1: [number, number]
  /** Segment endpoint 2 [lng, lat] */
  p2: [number, number]
  /** Compass bearing (degrees, 0=N, 90=E) of the TOLLED travel direction */
  tolledBearingDeg: number
  note: string
}

// Each segment spans the FULL water crossing (landing → landing) so a route on
// the deck stays within NEAR_M of the line anywhere along the span. p1 is the
// tolled-direction START landing, p2 the END landing, so tolledBearingDeg ≈ the
// travel bearing of p1→p2.
