// Live 511 traffic incidents + construction (work zones) near the express lanes.
// This is the app's one GENUINELY-LIVE feed (the toll feed is frozen), so it is
// labeled "LIVE traffic · 511" — distinct from the price readout, which must never
// be implied to be live. The server (/api/traffic) does the 511 fetch + road filter;
// here we add geometric proximity to the corridor/route the user is actually viewing.

export type TrafficKind = 'incident' | 'construction'
export type TrafficSeverity = 'major' | 'moderate' | 'minor' | 'unknown'

export interface TrafficItem {
  id: string
  kind: TrafficKind
  severity: TrafficSeverity
  headline: string
  road: string
  lng: number
  lat: number
  updated: string | null
}

export interface TrafficResponse {
  source: 'live' | 'sample' | 'none' | 'error'
  items: TrafficItem[]
  fetchedAt?: string
}

/** Trim 511's verbose headline: drop the "CHP : " / "Caltrans : " agency prefix and
 *  the trailing date clause, so it reads cleanly in both the panel and the map popup. */
export function cleanHeadline(h: string): string {
  return h
    .replace(/^[A-Za-z]+\s*:\s*/, '')
    .replace(/\s*(From|Starting|Expect)\b.*$/i, '')
    .trim()
}

export async function fetchTraffic(signal?: AbortSignal): Promise<TrafficResponse> {
  try {
    const res = await fetch('/api/traffic', { signal })
    if (!res.ok) return { source: 'error', items: [] }
    return (await res.json()) as TrafficResponse
  } catch {
    return { source: 'error', items: [] }
  }
}

type LngLat = [number, number]
const M_PER_DEG_LAT = 111_320

/** Meters from point p to segment a→b (equirectangular — fine at Bay Area scale). */
function distToSegM(p: LngLat, a: LngLat, b: LngLat): number {
  const lat = (((p[1] + a[1] + b[1]) / 3) * Math.PI) / 180
  const kx = M_PER_DEG_LAT * Math.cos(lat)
  const ky = M_PER_DEG_LAT
  const px = p[0] * kx, py = p[1] * ky
  const ax = a[0] * kx, ay = a[1] * ky
  const bx = b[0] * kx, by = b[1] * ky
  const dx = bx - ax, dy = by - ay
  const len2 = dx * dx + dy * dy
  let t = len2 ? ((px - ax) * dx + (py - ay) * dy) / len2 : 0
  t = Math.max(0, Math.min(1, t))
  return Math.hypot(px - (ax + t * dx), py - (ay + t * dy))
}

function minDistToPathM(p: LngLat, path: LngLat[]): number {
  let m = Infinity
  for (let i = 1; i < path.length; i++) m = Math.min(m, distToSegM(p, path[i - 1], path[i]))
  return m
}

/** Items whose point is within `maxM` meters of any of the given polylines. */
export function nearAny(items: TrafficItem[], polylines: LngLat[][], maxM: number): TrafficItem[] {
  const paths = polylines.filter((p) => p && p.length >= 2)
  if (!paths.length) return []
  return items.filter((it) => {
    const p: LngLat = [it.lng, it.lat]
    return paths.some((path) => minDistToPathM(p, path) <= maxM)
  })
}
