/**
 * Tiny TTL + LRU cache and an async deduper, used to avoid re-hitting the
 * keyless OSRM / Photon demo servers for inputs we've already resolved (reverse,
 * round-trip, recent re-picks, backspace-retype autocomplete).
 *
 * The clock is injectable so TTL behaviour is unit-testable without real time.
 */
export class TtlCache<V> {
  private map = new Map<string, { v: V; exp: number }>()

  constructor(
    private readonly max: number,
    private readonly ttlMs: number,
    private readonly now: () => number = () => Date.now(),
  ) {}

  get(key: string): V | undefined {
    const e = this.map.get(key)
    if (!e) return undefined
    if (e.exp <= this.now()) {
      this.map.delete(key)
      return undefined
    }
    // LRU touch: re-insert so it becomes most-recently-used.
    this.map.delete(key)
    this.map.set(key, e)
    return e.v
  }

  set(key: string, v: V): void {
    if (this.map.has(key)) this.map.delete(key)
    this.map.set(key, { v, exp: this.now() + this.ttlMs })
    while (this.map.size > this.max) {
      const oldest = this.map.keys().next().value
      if (oldest === undefined) break
      this.map.delete(oldest)
    }
  }

  get size(): number {
    return this.map.size
  }

  clear(): void {
    this.map.clear()
  }
}

/**
 * Wrap a cache with single-flight dedup: concurrent calls for the same key share
 * one in-flight promise, and only SUCCESSFUL resolutions are cached. If the
 * fetcher throws (e.g. AbortError or a transient HTTP error it chose to throw),
 * nothing is cached and the rejection propagates to every awaiting caller.
 *
 * Note: a resolved value of `undefined` cannot be cached (it's the miss
 * sentinel); use `null` for "successfully determined there is no result".
 */
export function createDeduper<V>(cache: TtlCache<V>) {
  const pending = new Map<string, Promise<V>>()
  return async function run(key: string, fetcher: () => Promise<V>): Promise<V> {
    const hit = cache.get(key)
    if (hit !== undefined) return hit
    const inflight = pending.get(key)
    if (inflight) return inflight
    const p = (async () => {
      const v = await fetcher()
      if (v !== undefined) cache.set(key, v)
      return v
    })()
    pending.set(key, p)
    try {
      return await p
    } finally {
      pending.delete(key)
    }
  }
}
