import { useEffect, useState } from 'react'
import type { FocusEvent, KeyboardEvent } from 'react'
import type { Occupancy } from '../lib/types'
import type { CorridorChipVM, OccOptionVM, ReadoutVM, StopVM, TimeSavingsVM } from '../lib/flexView'
import type { TrafficItem } from '../lib/traffic'
import { cleanHeadline } from '../lib/traffic'
import styles from './PlanPanel.module.css'

export interface PlanPanelProps {
  // address search
  fromText: string
  toText: string
  suggestions: { label: string; pick: () => void }[]
  showSuggest: boolean
  onFromInput: (v: string) => void
  onToInput: (v: string) => void
  onFromFocus: () => void
  onToFocus: () => void
  onSearchBlur: (e: FocusEvent<HTMLDivElement>) => void
  onCloseSuggest: () => void
  onSwap: () => void
  hasTrip: boolean
  tripMatchLabel: string
  onClearTrip: () => void
  // corridor header + browse
  badge: string
  corrName: string
  corrSub: string
  browseOpen: boolean
  browseLabel: string
  onToggleBrowse: () => void
  chips: CorridorChipVM[]
  onSelectCorridor: (id: string) => void
  // direction tabs
  directions: { id: string; label: string }[]
  directionId: string
  onSetDirection: (id: string) => void
  // readout
  readout: ReadoutVM
  announce: string
  tripMode: boolean
  timeSaved: TimeSavingsVM
  traffic: TrafficItem[]
  // stops
  stops: StopVM[]
  onPickStop: (i: number) => void
  // occupancy
  occOptions: OccOptionVM[]
  onSetOccupancy: (o: Occupancy) => void
  ruleHint: string
  // departure
  timeLabel: string
  isNow: boolean
  onSetNow: () => void
  minutes: number
  onTime: (m: number) => void
  curvePath: string
  curveArea: string
  markerLeft: string
  nowColor: string
  nowBg: string
  nowBorder: string
  // actions
  copyLabel: string
  onCopyLink: () => void
  bridgesOn: boolean
  onToggleBridges: () => void
}

export function PlanPanel(p: PlanPanelProps) {
  const r = p.readout
  // ARIA combobox: focus stays in the input; ArrowUp/Down move a virtual highlight
  // through the options (aria-activedescendant), Enter selects, Escape closes —
  // so the suggestions are fully keyboard-operable (WCAG 2.1.1) without the options
  // being separate tab stops.
  const [activeIdx, setActiveIdx] = useState(-1)
  const [savingsOpen, setSavingsOpen] = useState(false)
  useEffect(() => {
    setActiveIdx(-1)
  }, [p.showSuggest, p.fromText, p.toText])

  const onSearchKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (!p.showSuggest) return
    const n = p.suggestions.length
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setActiveIdx((i) => (i + 1) % n)
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setActiveIdx((i) => (i - 1 + n) % n)
    } else if (e.key === 'Enter') {
      if (activeIdx >= 0 && activeIdx < n) {
        e.preventDefault()
        p.suggestions[activeIdx].pick()
      }
    } else if (e.key === 'Escape') {
      p.onCloseSuggest()
    }
  }

  return (
    <section id="plan" tabIndex={-1} className={styles.panel} aria-label={`${p.corrName} fare planner`} data-testid="plan-panel">
      <div className={styles.inner}>
        {/* ── plan by address ── */}
        <div className={styles.search} onBlur={p.onSearchBlur}>
          <div className={styles.searchRow}>
            <div className={styles.odRail} aria-hidden="true">
              <span className={styles.odStart} />
              <span className={styles.odStem} />
              <span className={styles.odEnd} />
            </div>
            <div className={styles.searchInputs}>
              <input
                className={styles.input}
                value={p.fromText}
                onChange={(e) => p.onFromInput(e.target.value)}
                onFocus={p.onFromFocus}
                onKeyDown={onSearchKeyDown}
                placeholder="Start — city or address"
                aria-label="Start location"
                role="combobox"
                aria-expanded={p.showSuggest}
                aria-controls="fx-suggest"
                aria-autocomplete="list"
                aria-activedescendant={p.showSuggest && activeIdx >= 0 ? `fx-opt-${activeIdx}` : undefined}
                data-testid="from-input"
              />
              <input
                className={styles.input}
                value={p.toText}
                onChange={(e) => p.onToInput(e.target.value)}
                onFocus={p.onToFocus}
                onKeyDown={onSearchKeyDown}
                placeholder="Destination"
                aria-label="Destination"
                role="combobox"
                aria-expanded={p.showSuggest}
                aria-controls="fx-suggest"
                aria-autocomplete="list"
                aria-activedescendant={p.showSuggest && activeIdx >= 0 ? `fx-opt-${activeIdx}` : undefined}
                data-testid="to-input"
              />
            </div>
            <button className={styles.swap} onClick={p.onSwap} title="Swap start and destination" aria-label="Swap start and destination">
              ⇅
            </button>
          </div>
          {p.showSuggest && (
            <div className={styles.suggest} id="fx-suggest" role="listbox" aria-label="Location suggestions">
              {p.suggestions.map((s, i) => (
                <button
                  key={s.label + i}
                  id={`fx-opt-${i}`}
                  role="option"
                  aria-selected={i === activeIdx}
                  tabIndex={-1}
                  className={`${styles.suggestItem} ${i === activeIdx ? styles.suggestActive : ''}`}
                  onMouseDown={(e) => e.preventDefault()}
                  onClick={s.pick}
                  data-testid={`suggest-${i}`}
                >
                  <span className={styles.suggestIcon} aria-hidden="true">
                    ⌖
                  </span>
                  {s.label}
                </button>
              ))}
            </div>
          )}
          {p.hasTrip && (
            <div className={styles.tripMatch}>
              <span>{p.tripMatchLabel}</span>
              <button className={styles.clearTrip} onClick={p.onClearTrip} data-testid="clear-trip">
                clear
              </button>
            </div>
          )}
        </div>

        {/* ── departure (directly under start/end) ── */}
        <div className={styles.depHead}>
          <div className={styles.sectionLabel}>Departure · {p.timeLabel}</div>
          <button className={styles.nowBtn} style={{ color: p.nowColor, background: p.nowBg, borderColor: p.nowBorder }} onClick={p.onSetNow} aria-pressed={p.isNow} data-testid="time-now">
            ● Now
          </button>
        </div>
        <div className={styles.curve} data-testid="departure-curve">
          <svg viewBox="0 0 300 62" preserveAspectRatio="none" className={styles.curveSvg} aria-hidden="true">
            <path d={p.curveArea} className={styles.curveArea} />
            <path d={p.curvePath} className={styles.curvePath} />
          </svg>
          <span className={styles.curveMarker} style={{ left: p.markerLeft }} />
          <span className={styles.curveTickL}>5a</span>
          <span className={styles.curveTickR}>8p</span>
        </div>
        <input
          type="range"
          className={styles.range}
          min={300}
          max={1200}
          step={5}
          value={Math.max(300, Math.min(1200, p.minutes))}
          onChange={(e) => p.onTime(Number(e.target.value))}
          aria-label="Departure time"
          aria-valuetext={p.timeLabel}
          data-testid="time-slider"
        />
        {p.timeSaved.label && (
          <div className={styles.savingsWrap}>
            <button
              type="button"
              className={styles.savings}
              data-testid="time-saved"
              aria-expanded={savingsOpen}
              aria-controls="time-saved-detail"
              onClick={() => setSavingsOpen((v) => !v)}
            >
              <span className={styles.savingsBolt} aria-hidden="true">
                ⚡
              </span>
              Express lane {p.timeSaved.label} than general lanes
              <span className={styles.savingsNote}> · modeled</span>
              <span className={styles.savingsToggle} aria-hidden="true">
                {savingsOpen ? '▴ hide' : '▾ how?'}
              </span>
            </button>
            {savingsOpen && (
              <div className={styles.savingsDetail} id="time-saved-detail" data-testid="time-saved-detail">
                <p className={styles.savingsCaption}>
                  Over <strong>~{p.timeSaved.miles} mi</strong> of express lane on your route, departing {p.timeLabel}:
                </p>
                <div className={styles.bars}>
                  <div className={styles.barRow}>
                    <span className={styles.barName}>General</span>
                    <span className={styles.barTrack}>
                      <span className={`${styles.barFill} ${styles.barFillGp}`} style={{ width: '100%' }} />
                    </span>
                    <span className={styles.barVal}>
                      ~{p.timeSaved.generalMin} min<span className={styles.barMph}> · {p.timeSaved.generalMph} mph</span>
                    </span>
                  </div>
                  <div className={styles.barRow}>
                    <span className={styles.barName}>Express</span>
                    <span className={styles.barTrack}>
                      <span className={`${styles.barFill} ${styles.barFillEx}`} style={{ width: `${p.timeSaved.expressPct}%` }} />
                    </span>
                    <span className={styles.barVal}>
                      ~{p.timeSaved.expressMin} min<span className={styles.barMph}> · {p.timeSaved.expressMph} mph</span>
                    </span>
                  </div>
                </div>
                <p className={styles.savingsMath}>
                  60 × {p.timeSaved.miles} mi × (1/{p.timeSaved.generalMph} − 1/{p.timeSaved.expressMph}) ≈{' '}
                  <strong>{p.timeSaved.minutes} min saved</strong>
                </p>
                <p className={styles.savingsSrc}>
                  Express miles are measured from your route. Lane speeds are <strong>modeled</strong> from the same
                  time-of-day congestion model that sets the toll prices above — there is no public keyless live-traffic
                  feed, so this is an estimate, not a live measurement. For scale, VTA reports SR-237 express saves 5–20
                  min at peak and MTC reports I-680 express runs ~9–17 mph faster than the general lanes.
                </p>
              </div>
            )}
          </div>
        )}

        {/* ── corridor header ── */}
        <div className={styles.corrHead}>
          <span className={styles.corrBadge}>{p.badge}</span>
          <div className={styles.corrTitleWrap}>
            <h1 className={styles.corrName}>{p.corrName}</h1>
            <p className={styles.corrSub}>{p.corrSub}</p>
          </div>
          <button className={styles.browseBtn} onClick={p.onToggleBrowse} aria-expanded={p.browseOpen} aria-controls="corridor-browse" title="Browse all corridors" data-testid="browse-toggle">
            {p.browseLabel}
          </button>
        </div>

        {/* ── browse list ── */}
        {p.browseOpen && (
          <div className={styles.browse} id="corridor-browse">
            {p.chips.map((c) => (
              <button key={c.id} className={`${styles.browseRow} ${c.selected ? styles.browseRowOn : ''}`} onClick={() => p.onSelectCorridor(c.id)} data-testid={`corridor-${c.id}`}>
                <span className={styles.browseDot} style={{ background: c.color, borderRadius: c.hasLive ? '50%' : '2px' }} />
                <span className={styles.browseBadge}>{c.badge}</span>
                <span className={styles.browseName}>{c.name}</span>
                <span className={styles.browsePrice} style={{ color: c.color }}>
                  {c.browsePriceLabel}
                </span>
              </button>
            ))}
          </div>
        )}

        {/* ── direction tabs ── */}
        {p.directions.length > 1 && (
          <div className={styles.dirTabs} role="group" aria-label="Direction of travel">
            {p.directions.map((d) => {
              const on = d.id === p.directionId
              return (
                <button key={d.id} aria-pressed={on} className={`${styles.dirTab} ${on ? styles.dirTabOn : ''}`} onClick={() => p.onSetDirection(d.id)} data-testid={`dir-${d.id}`}>
                  {d.label}
                </button>
              )
            })}
          </div>
        )}

        {/* ── DMS readout (answer-first) ── */}
        <div className={styles.dms} data-testid="dms-readout">
          <div className={styles.dmsTop}>
            <span className={styles.dmsLabel}>{r.readoutLabel}</span>
            <span className={styles.dmsBadge} style={{ color: r.badge.color, background: r.badge.bg, borderColor: r.badge.border }} data-testid="feed-badge">
              {r.badge.pulse && <span className={styles.dmsBadgeDot} style={{ background: r.badge.color }} />}
              {r.badge.text}
            </span>
          </div>
          <div className={styles.dmsPrice} style={{ fontSize: `${r.priceSize}px`, color: r.priceColor, textShadow: r.priceGlow }} data-testid="fare-amount">
            {r.priceText}
          </div>
          {r.isFree && r.freeReason && <div className={styles.dmsFree}>{r.freeReason}</div>}
          <div className={styles.dmsBreak}>
            {r.breakdown.map((b, i) => (
              <div key={i} className={styles.dmsRow}>
                <span style={{ color: b.labelColor }}>{b.label}</span>
                <span className={styles.dmsAmt} style={{ color: b.amountColor }}>
                  {b.amount}
                </span>
              </div>
            ))}
            <div className={styles.dmsTotal}>
              <span>{r.totalLabel}</span>
              <span className={styles.dmsTotalAmt} style={{ color: r.priceColor }}>
                {r.priceText}
              </span>
            </div>
          </div>
          <div className={styles.dmsReason}>{r.tolledReason}</div>
        </div>
        {/* screen-reader announcement of the current answer (price changes silently otherwise) */}
        <div className={styles.srOnly} role="status" aria-live="polite">
          {p.announce}
        </div>

        {/* ── live conditions: the one genuinely-live feed (distinct from the frozen price) ── */}
        <div className={styles.conditions} data-testid="conditions">
          <div className={styles.condHead}>
            <span className={styles.condTitle}>{p.tripMode ? 'Conditions on route' : 'Conditions'}</span>
            <span className={styles.condLive} title="Live CHP/Caltrans incidents from the 511 traffic feed — this feed IS live (unlike the toll prices, which are a time-of-day estimate).">
              <span className={styles.condLiveDot} aria-hidden="true" /> LIVE traffic · 511
            </span>
          </div>
          {p.traffic.length === 0 ? (
            <div className={styles.condClear} data-testid="cond-clear">
              No active incidents reported{p.tripMode ? ' on your route' : ' on this corridor'}
            </div>
          ) : (
            <ul className={styles.condList}>
              {p.traffic.slice(0, 4).map((t) => (
                <li key={t.id} className={styles.condItem} data-testid="cond-item">
                  <span className={`${styles.condIcon} ${t.kind === 'incident' ? styles.condIncident : styles.condWork}`} aria-hidden="true">
                    {t.kind === 'incident' ? '⚠' : '⛟'}
                  </span>
                  <span className={styles.condText}>
                    <span className={styles.condRoad}>{t.road}</span> {cleanHeadline(t.headline)}
                  </span>
                </li>
              ))}
              {p.traffic.length > 4 && (
                <li className={styles.condMore} data-testid="cond-more">
                  +{p.traffic.length - 4} more nearby
                </li>
              )}
            </ul>
          )}
        </div>

        {/* ── stops (corridor mode only; in trip mode the route defines the span) ── */}
        {!p.tripMode && (
          <>
            <div className={styles.sectionLabel}>Trip · tap two stops</div>
            <div className={styles.stops}>
              {p.stops.map((st) => (
                <button key={st.i} className={styles.stopRow} onClick={() => p.onPickStop(st.i)} data-testid={`stop-${st.i}`} aria-label={`Stop ${st.label}${st.tag ? ` (${st.tag})` : ''}`}>
                  <span className={styles.stopRail}>
                    <span className={styles.stopConnTop} style={{ background: st.connTop }} />
                    <span className={styles.stopConnBot} style={{ background: st.connBot }} />
                    <span className={styles.stopDot} style={{ width: st.dotSize, height: st.dotSize, background: st.dotBg, borderColor: st.dotBorder, boxShadow: st.dotShadow }} />
                  </span>
                  <span className={styles.stopLabel} style={{ color: st.labelColor, fontWeight: st.labelWeight }}>
                    {st.label}
                    {st.tag && (
                      <span className={styles.stopTag} style={{ color: st.tagColor }}>
                        {st.tag}
                      </span>
                    )}
                  </span>
                </button>
              ))}
            </div>
          </>
        )}

        {/* ── occupancy ── */}
        <div className={styles.sectionLabel}>FasTrak Flex · who&apos;s aboard</div>
        <div className={styles.occ}>
          {p.occOptions.map((o) => (
            <button
              key={o.id}
              className={styles.occBtn}
              style={{ background: o.bg, border: o.border }}
              aria-pressed={o.selected}
              onClick={() => p.onSetOccupancy(o.id)}
              data-testid={`flex-${o.id}`}
            >
              <span className={styles.occIcon} aria-hidden="true">
                {o.icon}
              </span>
              <span className={styles.occTitle} style={{ color: o.titleColor }}>
                {o.title}
              </span>
              <span className={styles.occSub} style={{ color: o.subColor }}>
                {o.sub}
              </span>
            </button>
          ))}
        </div>
        <p className={styles.ruleHint}>{p.ruleHint}</p>

        {/* ── actions ── */}
        <div className={styles.actions}>
          <button className={styles.copyBtn} onClick={p.onCopyLink} data-testid="copy-link">
            {p.copyLabel}
          </button>
          <button className={`${styles.bridgesBtn} ${p.bridgesOn ? styles.bridgesOn : ''}`} onClick={p.onToggleBridges} aria-pressed={p.bridgesOn} data-testid="bridges-toggle">
            ⛉ Bridges
          </button>
        </div>
        <p className={styles.foot}>
          Live posted prices from the 511 SF Bay toll feed where signs report; a clearly-labeled time-of-day estimate elsewhere. The posted price at the gantry governs. Not affiliated with MTC / 511 / FasTrak.
        </p>
      </div>
    </section>
  )
}
