import styles from './TopBar.module.css'

export interface TopBarProps {
  feedLabel: string
  feedColor: string
  feedLive: boolean
  updatedLabel: string
  onRefresh: () => void
  theme: 'dark' | 'light'
  onToggleTheme: () => void
}

export function TopBar({ feedLabel, feedColor, feedLive, updatedLabel, onRefresh, theme, onToggleTheme }: TopBarProps) {
  return (
    <header className={styles.bar}>
      <div className={styles.brand}>
        <span className={styles.logo} aria-hidden="true">
          ◇
        </span>
        <div>
          <div className={styles.brandName}>Flex Lane Fares</div>
          <div className={styles.brandSub}>Bay Area express lanes</div>
        </div>
      </div>
      <div className={styles.tools}>
        <button className={styles.feed} onClick={onRefresh} title={`${updatedLabel} · tap to refresh`} data-testid="refresh-live" style={{ color: feedColor }}>
          <span className={`${styles.dot} ${feedLive ? styles.dotPulse : ''}`} style={{ background: feedColor }} />
          {feedLabel}
        </button>
        <button className={styles.theme} onClick={onToggleTheme} title="Toggle base map" data-testid="theme-toggle">
          {theme === 'dark' ? '◑ Light map' : '◐ Dark map'}
        </button>
      </div>
    </header>
  )
}
