import { useEffect, useRef } from 'react'
import maplibregl from 'maplibre-gl'
import 'maplibre-gl/dist/maplibre-gl.css'
import { geoById } from '../data/geo'
import geoPaths from '../data/geo-paths.json'
import type { CorridorChipVM } from '../lib/flexView'
import { C } from '../lib/flexView'
import type { TrafficItem } from '../lib/traffic'
import { cleanHeadline } from '../lib/traffic'
import styles from './FlexMap.module.css'

type LngLat = [number, number]
const ROAD_PATHS = geoPaths as unknown as Record<string, LngLat[]>

export interface BridgePin {
  name: string
  lng: number
  lat: number
  tollLabel: string
  live: boolean
}

export interface FlexMapProps {
  chips: CorridorChipVM[]
  selectedId: string
  entryFrac: number
  exitFrac: number
  theme: 'dark' | 'light'
  bridgesOn: boolean
  bridges: BridgePin[]
  /** The actual OSRM driving route (road-following) when an address trip is planned. */
  routeCoords: LngLat[] | null
  /** The express-lane portions the route uses (highlighted over the route). */
  matchSpans: LngLat[][]
  /** Live 511 incidents/work-zones near the viewed corridor/route (markers). */
  traffic: TrafficItem[]
  onSelect: (id: string) => void
}

// Road-following polyline (OSRM-traced in server/gen-geo-paths.mjs) so the lane
// sits on the real freeway when zoomed in; falls back to the gantry points.
export function corridorCoords(id: string): LngLat[] {
  const road = ROAD_PATHS[id]
  if (road && road.length >= 2) return road
  return (geoById(id)?.points ?? []).map((p) => [p.lng, p.lat] as LngLat)
}

function ptAt(pts: LngLat[], f: number): LngLat {
  if (pts.length < 2) return pts[0] ?? [0, 0]
  const seg: number[] = []
  let tot = 0
  for (let i = 1; i < pts.length; i++) {
    const d = Math.hypot(pts[i][0] - pts[i - 1][0], pts[i][1] - pts[i - 1][1])
    seg.push(d)
    tot += d
  }
  let t = Math.max(0, Math.min(1, f)) * tot
  for (let i = 1; i < pts.length; i++) {
    const d = seg[i - 1]
    if (t <= d || i === pts.length - 1) {
      const k = d ? t / d : 0
      return [pts[i - 1][0] + (pts[i][0] - pts[i - 1][0]) * k, pts[i - 1][1] + (pts[i][1] - pts[i - 1][1]) * k]
    }
    t -= d
  }
  return pts[pts.length - 1]
}

function subPath(pts: LngLat[], f1: number, f2: number): LngLat[] {
  const a = Math.min(f1, f2)
  const b = Math.max(f1, f2)
  const s = ptAt(pts, a)
  const e = ptAt(pts, b)
  const seg: number[] = []
  let tot = 0
  for (let i = 1; i < pts.length; i++) {
    const d = Math.hypot(pts[i][0] - pts[i - 1][0], pts[i][1] - pts[i - 1][1])
    seg.push(d)
    tot += d
  }
  const mid: LngLat[] = []
  let cum = 0
  for (let i = 0; i < pts.length; i++) {
    const fr = tot ? cum / tot : 0
    if (fr > a && fr < b) mid.push(pts[i])
    if (i < seg.length) cum += seg[i]
  }
  return [s, ...mid, e]
}

// Inline style: CARTO RASTER basemap (reliable, no big vector-style fetch that
// can hang on a slow CDN and blank the corridor overlay).
function styleSpec(theme: 'dark' | 'light'): maplibregl.StyleSpecification {
  const set = theme === 'light' ? 'light_all' : 'dark_all'
  const tiles = ['a', 'b', 'c'].map((s) => `https://${s}.basemaps.cartocdn.com/${set}/{z}/{x}/{y}{r}.png`)
  return {
    version: 8,
    sources: { carto: { type: 'raster', tiles, tileSize: 256, attribution: '© CARTO © OpenStreetMap contributors' } },
    layers: [
      { id: 'bg', type: 'background', paint: { 'background-color': theme === 'light' ? '#e8eaed' : '#06080a' } },
      { id: 'carto', type: 'raster', source: 'carto' },
    ],
  }
}

export function FlexMap(props: FlexMapProps) {
  const { theme } = props
  const containerRef = useRef<HTMLDivElement>(null)
  const mapRef = useRef<maplibregl.Map | null>(null)
  const loadedRef = useRef(false)
  const markersRef = useRef<Record<string, maplibregl.Marker>>({})
  const bridgeMarkersRef = useRef<maplibregl.Marker[]>([])
  const trafficMarkersRef = useRef<maplibregl.Marker[]>([])
  const startRef = useRef<maplibregl.Marker | null>(null)
  const endRef = useRef<maplibregl.Marker | null>(null)
  // Latest props for imperative handlers that close over stale values.
  const propsRef = useRef(props)
  propsRef.current = props

  function addLayers(map: maplibregl.Map) {
    if (map.getSource('corridors')) return
    map.addSource('corridors', { type: 'geojson', promoteId: 'id', data: { type: 'FeatureCollection', features: [] } })
    map.addLayer({
      id: 'cor-glow',
      type: 'line',
      source: 'corridors',
      layout: { 'line-cap': 'round', 'line-join': 'round' },
      paint: {
        'line-color': ['get', 'color'],
        'line-width': ['case', ['boolean', ['feature-state', 'selected'], false], 20, 9],
        'line-blur': 10,
        'line-opacity': ['case', ['boolean', ['feature-state', 'selected'], false], 0.5, 0.16],
      },
    })
    map.addLayer({
      id: 'cor-line',
      type: 'line',
      source: 'corridors',
      filter: ['!', ['to-boolean', ['get', 'estimate']]],
      layout: { 'line-cap': 'round', 'line-join': 'round' },
      paint: {
        'line-color': ['get', 'color'],
        'line-width': ['case', ['boolean', ['feature-state', 'selected'], false], 7, 3.5],
        'line-opacity': ['case', ['boolean', ['feature-state', 'selected'], false], 1, ['case', ['get', 'tolledNow'], 0.92, 0.5]],
      },
    })
    map.addLayer({
      id: 'cor-est',
      type: 'line',
      source: 'corridors',
      filter: ['to-boolean', ['get', 'estimate']],
      layout: { 'line-cap': 'butt', 'line-join': 'round' },
      paint: {
        'line-color': ['get', 'color'],
        'line-width': ['case', ['boolean', ['feature-state', 'selected'], false], 7, 3.5],
        'line-dasharray': [1.5, 2],
        'line-opacity': ['case', ['boolean', ['feature-state', 'selected'], false], 1, ['case', ['get', 'tolledNow'], 0.92, 0.5]],
      },
    })
    map.addLayer({ id: 'cor-hit', type: 'line', source: 'corridors', layout: { 'line-cap': 'round', 'line-join': 'round' }, paint: { 'line-color': '#000', 'line-width': 24, 'line-opacity': 0 } })
    map.addSource('trip', { type: 'geojson', data: { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: [] } } })
    map.addLayer({ id: 'trip-line', type: 'line', source: 'trip', layout: { 'line-cap': 'round', 'line-join': 'round' }, paint: { 'line-color': '#ffffff', 'line-width': 5.5, 'line-opacity': 0.95 } })
    map.addSource('aroute', { type: 'geojson', data: { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: [] } } })
    map.addLayer({ id: 'aroute-line', type: 'line', source: 'aroute', layout: { 'line-cap': 'round', 'line-join': 'round' }, paint: { 'line-color': '#5ad1ff', 'line-width': 4, 'line-opacity': 0.85, 'line-dasharray': [2, 1.6] } })
    // Express-lane portions the planned route actually uses (drawn over the cyan route).
    map.addSource('match', { type: 'geojson', data: { type: 'Feature', properties: {}, geometry: { type: 'MultiLineString', coordinates: [] } } })
    map.addLayer({ id: 'match-glow', type: 'line', source: 'match', layout: { 'line-cap': 'round', 'line-join': 'round' }, paint: { 'line-color': '#ffb000', 'line-width': 14, 'line-blur': 8, 'line-opacity': 0.4 } })
    map.addLayer({ id: 'match-line', type: 'line', source: 'match', layout: { 'line-cap': 'round', 'line-join': 'round' }, paint: { 'line-color': '#ffd166', 'line-width': 6, 'line-opacity': 0.98 } })
  }

  function syncChips(map: maplibregl.Map) {
    const { chips, selectedId } = propsRef.current
    for (const chip of chips) {
      const coords = corridorCoords(chip.id)
      if (coords.length < 2) continue
      const at = ptAt(coords, 0.5)
      let mk = markersRef.current[chip.id]
      if (!mk) {
        const el = document.createElement('div')
        el.className = styles.chip
        el.setAttribute('data-testid', `chip-${chip.id}`)
        el.addEventListener('click', (ev) => {
          ev.stopPropagation()
          propsRef.current.onSelect(chip.id)
        })
        mk = new maplibregl.Marker({ element: el, anchor: 'center' }).setLngLat(at).addTo(map)
        markersRef.current[chip.id] = mk
      }
      const sel = chip.id === selectedId
      const el = mk.getElement()
      const c = chip.color
      el.style.background = sel ? c : 'rgba(7,10,9,.92)'
      el.style.color = sel ? (c === C.amber ? '#1a1205' : '#04140b') : c
      el.style.border = `1px solid ${sel ? c : c === C.idle ? '#3a4049' : c === C.green ? 'rgba(53,208,122,.4)' : 'rgba(255,176,0,.4)'}`
      el.style.boxShadow = sel ? `0 0 18px ${c === C.amber ? 'rgba(255,176,0,.5)' : 'rgba(53,208,122,.5)'}` : '0 2px 8px rgba(0,0,0,.5)'
      el.style.zIndex = sel ? '3' : '1'
      el.textContent = `${chip.badge} ${chip.chipLabel}`
      mk.setLngLat(at)
    }
  }

  function syncBridges(map: maplibregl.Map) {
    const { bridgesOn, bridges } = propsRef.current
    for (const b of bridgeMarkersRef.current) b.remove()
    bridgeMarkersRef.current = []
    if (!bridgesOn) return
    for (const b of bridges) {
      const el = document.createElement('div')
      el.className = styles.bridgePin
      el.innerHTML = `<span class="${styles.bridgeLabel}">⛉ ${b.tollLabel}</span>`
      el.setAttribute('title', `${b.name} Bridge — ${b.live ? 'posted' : 'typical'} toll ${b.tollLabel}`)
      const mk = new maplibregl.Marker({ element: el, anchor: 'bottom' }).setLngLat([b.lng, b.lat]).addTo(map)
      bridgeMarkersRef.current.push(mk)
    }
  }

  function syncTraffic(map: maplibregl.Map) {
    const { traffic } = propsRef.current
    for (const m of trafficMarkersRef.current) m.remove()
    trafficMarkersRef.current = []
    for (const t of traffic) {
      const el = document.createElement('div')
      el.className = `${styles.trafficPin} ${t.kind === 'incident' ? styles.trafficIncident : styles.trafficWork}`
      el.textContent = t.kind === 'incident' ? '⚠' : '⛟'
      el.setAttribute('title', `${t.road}: ${cleanHeadline(t.headline)}`)
      const popup = new maplibregl.Popup({ offset: 14, closeButton: false, className: styles.trafficPopup }).setText(`${t.road} — ${cleanHeadline(t.headline)}`)
      const mk = new maplibregl.Marker({ element: el, anchor: 'center' }).setLngLat([t.lng, t.lat]).setPopup(popup).addTo(map)
      trafficMarkersRef.current.push(mk)
    }
  }

  function syncEndpoints(map: maplibregl.Map, route: LngLat[] | null) {
    if (!route || route.length < 2) {
      startRef.current?.remove()
      endRef.current?.remove()
      startRef.current = null
      endRef.current = null
      return
    }
    const ensure = (ref: typeof startRef, kind: 'start' | 'end', at: LngLat) => {
      let mk = ref.current
      if (!mk) {
        const el = document.createElement('div')
        el.className = kind === 'start' ? `${styles.endpoint} ${styles.endStart}` : `${styles.endpoint} ${styles.endFinish}`
        el.title = kind === 'start' ? 'Start' : 'Destination'
        mk = new maplibregl.Marker({ element: el, anchor: 'center' }).setLngLat(at).addTo(map)
        ref.current = mk
      } else {
        mk.setLngLat(at)
      }
    }
    ensure(startRef, 'start', route[0])
    ensure(endRef, 'end', route[route.length - 1])
  }

  function syncAll() {
    const map = mapRef.current
    if (!map || !loadedRef.current) return
    const { chips, selectedId, entryFrac, exitFrac, routeCoords, matchSpans } = propsRef.current
    const feats = chips
      .map((chip) => {
        const coords = corridorCoords(chip.id)
        if (coords.length < 2) return null
        return {
          type: 'Feature' as const,
          id: chip.id,
          properties: { id: chip.id, color: chip.color, tolledNow: chip.tolledNow, estimate: !chip.hasLive },
          geometry: { type: 'LineString' as const, coordinates: coords },
        }
      })
      .filter(Boolean) as GeoJSON.Feature[]
    const src = map.getSource('corridors') as maplibregl.GeoJSONSource | undefined
    src?.setData({ type: 'FeatureCollection', features: feats })
    for (const chip of chips) {
      try {
        map.setFeatureState({ source: 'corridors', id: chip.id }, { selected: chip.id === selectedId })
      } catch {
        /* feature not loaded yet */
      }
    }
    const tripActive = !!(routeCoords && routeCoords.length >= 2)
    // Selected-corridor span (white) — corridor mode only; cleared in trip mode.
    const coords = corridorCoords(selectedId)
    const tripSrc = map.getSource('trip') as maplibregl.GeoJSONSource | undefined
    tripSrc?.setData(
      !tripActive && coords.length >= 2
        ? { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: subPath(coords, entryFrac, exitFrac) } }
        : { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: [] } },
    )
    // Full driving route (cyan dashed) — follows the real road network.
    const aSrc = map.getSource('aroute') as maplibregl.GeoJSONSource | undefined
    aSrc?.setData(
      tripActive
        ? { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: routeCoords as LngLat[] } }
        : { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: [] } },
    )
    // Express-lane portions used (amber, on top of the route).
    const mSrc = map.getSource('match') as maplibregl.GeoJSONSource | undefined
    mSrc?.setData(
      tripActive && matchSpans.length
        ? { type: 'Feature', properties: {}, geometry: { type: 'MultiLineString', coordinates: matchSpans } }
        : { type: 'Feature', properties: {}, geometry: { type: 'MultiLineString', coordinates: [] } },
    )
    syncChips(map)
    syncBridges(map)
    syncTraffic(map)
    syncEndpoints(map, tripActive ? (routeCoords as LngLat[]) : null)
  }

  function fitCoords(coords: LngLat[]) {
    const map = mapRef.current
    if (!map || coords.length < 2) return
    let w = 180,
      s = 90,
      e = -180,
      n = -90
    for (const c of coords) {
      if (!c || c.length < 2) continue
      w = Math.min(w, c[0])
      e = Math.max(e, c[0])
      s = Math.min(s, c[1])
      n = Math.max(n, c[1])
    }
    if (w > e) return
    try {
      map.fitBounds([[w, s], [e, n]], { padding: { top: 90, bottom: 60, left: 60, right: 90 }, maxZoom: 12.5, duration: 700 })
    } catch {
      /* fitBounds can throw mid-style-swap; harmless */
    }
  }
  function fit(id: string) {
    fitCoords(corridorCoords(id))
  }

  // ── Init once ──
  useEffect(() => {
    if (!containerRef.current || mapRef.current) return
    const map = new maplibregl.Map({
      container: containerRef.current,
      style: styleSpec(propsRef.current.theme),
      center: [-122.02, 37.72],
      zoom: 8.4,
      minZoom: 7,
      maxZoom: 15,
      attributionControl: { compact: true },
    })
    mapRef.current = map
    ;(window as unknown as { __FXMAP?: unknown }).__FXMAP = map
    // Basemap tile/network hiccups are non-fatal — overlay + interactions work
    // regardless. Swallow so they don't spam the console (e2e asserts zero errors).
    map.on('error', () => {})
    map.addControl(new maplibregl.NavigationControl({ showCompass: false }), 'bottom-right')

    // Bind layer interaction ONCE here (not in addLayers): a theme swap removes +
    // re-adds the layers, so binding inside addLayers would stack a duplicate set
    // of click/hover listeners on every toggle. Layer-scoped handlers registered
    // before the layer exists still fire once it does.
    map.on('mouseenter', 'cor-hit', () => {
      map.getCanvas().style.cursor = 'pointer'
    })
    map.on('mouseleave', 'cor-hit', () => {
      map.getCanvas().style.cursor = ''
    })
    map.on('click', 'cor-hit', (e) => {
      const id = e.features?.[0]?.id
      if (id) propsRef.current.onSelect(String(id))
    })

    const styleReady = () => {
      try {
        return !!(map.style && map.getStyle())
      } catch {
        return false
      }
    }
    const onLoad = () => {
      if (loadedRef.current || !styleReady()) return
      try {
        addLayers(map)
        if (!map.getSource('corridors')) return
        loadedRef.current = true
        syncAll()
        fit(propsRef.current.selectedId)
      } catch {
        loadedRef.current = false
      }
    }
    map.on('load', onLoad)
    map.on('styledata', onLoad)
    map.on('idle', onLoad)
    let polls = 0
    const poll = () => {
      if (loadedRef.current) return
      onLoad()
      if (loadedRef.current) return
      if (polls++ < 100) setTimeout(poll, 150)
    }
    setTimeout(poll, 200)

    return () => {
      for (const k of Object.keys(markersRef.current)) markersRef.current[k].remove()
      markersRef.current = {}
      for (const b of bridgeMarkersRef.current) b.remove()
      bridgeMarkersRef.current = []
      for (const m of trafficMarkersRef.current) m.remove()
      trafficMarkersRef.current = []
      startRef.current?.remove()
      endRef.current?.remove()
      startRef.current = null
      endRef.current = null
      loadedRef.current = false
      try {
        map.remove()
      } catch {
        /* already gone */
      }
      mapRef.current = null
    }
  }, [])

  // ── Re-sync overlay on any data/selection change ──
  useEffect(() => {
    syncAll()
  }, [props.chips, props.selectedId, props.entryFrac, props.exitFrac, props.routeCoords, props.matchSpans, props.bridgesOn, props.bridges, props.traffic])

  // ── Fit to the selected corridor (unless a planned route owns the viewport) ──
  useEffect(() => {
    if (loadedRef.current && !(props.routeCoords && props.routeCoords.length >= 2)) fit(props.selectedId)
  }, [props.selectedId])

  // ── Fit to the planned driving route when one is set; back to the corridor on clear ──
  useEffect(() => {
    if (!loadedRef.current) return
    const r = props.routeCoords
    if (r && r.length >= 2) fitCoords(r)
    else fit(props.selectedId)
  }, [props.routeCoords])

  // ── Theme swap: restyle, then re-add the overlay once the spec is parsed ──
  useEffect(() => {
    const map = mapRef.current
    if (!map || !loadedRef.current) return
    loadedRef.current = false
    map.setStyle(styleSpec(theme))
    let tries = 0
    const reAdd = () => {
      if (loadedRef.current) return
      let ok = false
      try {
        ok = !!(map.style && map.getStyle())
      } catch {
        ok = false
      }
      if (!ok) {
        if (tries++ < 60) setTimeout(reAdd, 120)
        return
      }
      if (!map.getSource('corridors')) addLayers(map)
      if (map.getSource('corridors')) {
        loadedRef.current = true
        syncAll()
      }
    }
    setTimeout(reAdd, 150)
  }, [theme])

  return <div ref={containerRef} className={styles.map} data-testid="flex-map" role="region" aria-label="Bay Area express lane network map" />
}
