import type { AccessPoint, Direction } from './types'
import type { LiveZoneMap } from './pricing'

export interface LiveZoneFeed {
  index: number
  fromLabel: string
  toLabel: string
  price: number
  lastUpdated: string | null
}

export interface LiveProgram {
  program: string
  authority: string
  signCount: number
  asOf: string | null
  zones: LiveZoneFeed[]
  points: { label: string }[]
  staleMin: number
  fresh: boolean
  source: 'live' | 'sample'
}

export interface BridgeToll {
  name: string
  authority: string
  price: number | null
  minToll: number | null
  maxToll: number | null
  lastUpdated: string | null
}

export interface LiveResponse {
  source: 'live' | 'sample' | 'none' | 'error'
  programs: Record<string, LiveProgram>
  bridges: BridgeToll[]
  asOf: string | null
  fetchedAt?: string
  error?: string
}

export const EMPTY_LIVE: LiveResponse = { source: 'none', programs: {}, bridges: [], asOf: null }

export async function fetchLive(signal?: AbortSignal): Promise<LiveResponse> {
  try {
    const res = await fetch('/api/live', { signal })
    if (!res.ok) return { ...EMPTY_LIVE, source: 'error', error: `HTTP ${res.status}` }
    return (await res.json()) as LiveResponse
  } catch (err) {
    if ((err as Error).name === 'AbortError') return EMPTY_LIVE
    return { ...EMPTY_LIVE, source: 'error', error: String((err as Error).message) }
  }
}

/** The live program for a direction, only if present AND fresh. */
export function liveProgramFor(live: LiveResponse, direction: Direction): LiveProgram | null {
  if (!direction.live) return null
  const p = live.programs[direction.live.program]
  if (!p || !p.fresh || p.zones.length === 0) return null
  return p
}

/** The most recent program reading for a direction, fresh or stale (for the "last reported" chip). */
export function lastReportedFor(live: LiveResponse, direction: Direction): LiveProgram | null {
  if (!direction.live) return null
  return live.programs[direction.live.program] ?? null
}

export interface ActiveDirection {
  id: string
  label: string
  points: AccessPoint[]
  lengthMiles?: number | null
  liveMap: LiveZoneMap | null
  liveProgram: LiveProgram | null
}

/**
 * Resolve the direction the UI should actually render. When fresh live data
 * exists, use the feed's gantries and per-zone prices; otherwise the static
 * points with an estimator.
 */
export function resolveDirection(direction: Direction, live: LiveResponse): ActiveDirection {
  const program = liveProgramFor(live, direction)
  if (program) {
    const points: AccessPoint[] = program.points.map((p, i) => ({ id: `live-${i}`, label: p.label, known: true }))
    const liveMap: LiveZoneMap = {}
    for (const z of program.zones) {
      liveMap[z.index] = { price: z.price, lastUpdated: z.lastUpdated, source: program.source }
    }
    return {
      id: direction.id,
      label: direction.label,
      points,
      lengthMiles: direction.lengthMiles,
      liveMap,
      liveProgram: program,
    }
  }
  return {
    id: direction.id,
    label: direction.label,
    points: direction.points,
    lengthMiles: direction.lengthMiles,
    liveMap: null,
    liveProgram: null,
  }
}
