// Map-match a driving route against the express-lane corridors to detect which
// lanes (and how many zones) the route actually uses. Approximate — thresholds are
// tuned empirically; results feed the MODELED toll estimate, not posted prices.
import geoPaths from '../data/geo-paths.json'
import { geoCorridors } from '../data/geo'

type LngLat = [number, number]
const PATHS = geoPaths as unknown as Record<string, LngLat[]>

const NEAR_M = 110 // a route point this close to a corridor counts as "on" it
const MIN_RUN_M = 800 // a match needs at least this much continuous route overlap
const MIN_CORRIDOR_M = 1500 // ...and must cover at least this much of the corridor (kills interchange clips)
const SAMPLE_M = 50 // resample the route to ~this spacing before matching

const M_PER_DEG_LAT = 111_320
const mPerDegLng = (lat: number) => 111_320 * Math.cos((lat * Math.PI) / 180)

function distM(a: LngLat, b: LngLat): number {
  const lat = (a[1] + b[1]) / 2
  const dx = (a[0] - b[0]) * mPerDegLng(lat)
  const dy = (a[1] - b[1]) * M_PER_DEG_LAT
  return Math.hypot(dx, dy)
}

function nearestOnSeg(p: LngLat, a: LngLat, b: LngLat): { dist: number; t: number } {
  const lat = (a[1] + b[1]) / 2
  const mlng = mPerDegLng(lat)
  const ax = a[0] * mlng,
    ay = a[1] * M_PER_DEG_LAT,
    bx = b[0] * mlng,
    by = b[1] * M_PER_DEG_LAT,
    px = p[0] * mlng,
    py = p[1] * M_PER_DEG_LAT
  const dx = bx - ax,
    dy = by - ay
  const len2 = dx * dx + dy * dy
  let t = len2 ? ((px - ax) * dx + (py - ay) * dy) / len2 : 0
  t = Math.max(0, Math.min(1, t))
  const cx = ax + dx * t,
    cy = ay + dy * t
  return { dist: Math.hypot(px - cx, py - cy), t }
}

function buildCum(path: LngLat[]): { seg: number[]; total: number } {
  const seg: number[] = []
  let total = 0
  for (let i = 1; i < path.length; i++) {
    const d = distM(path[i - 1], path[i])
    seg.push(d)
    total += d
  }
  return { seg, total }
}

function nearestOnPath(path: LngLat[], seg: number[], total: number, p: LngLat): { dist: number; frac: number } {
  let best = { dist: Infinity, frac: 0 }
  let cum = 0
  for (let i = 1; i < path.length; i++) {
    const { dist, t } = nearestOnSeg(p, path[i - 1], path[i])
    if (dist < best.dist) best = { dist, frac: total ? (cum + seg[i - 1] * t) / total : 0 }
    cum += seg[i - 1]
  }
  return best
}

function pointAtFraction(path: LngLat[], seg: number[], total: number, f: number): LngLat {
  if (path.length < 2) return path[0] ?? [0, 0]
  let target = Math.max(0, Math.min(1, f)) * total
  for (let i = 1; i < path.length; i++) {
    const d = seg[i - 1]
    if (target <= d || i === path.length - 1) {
      const t = d ? target / d : 0
      return [path[i - 1][0] + (path[i][0] - path[i - 1][0]) * t, path[i - 1][1] + (path[i][1] - path[i - 1][1]) * t]
    }
    target -= d
  }
  return path[path.length - 1]
}

function subPath(path: LngLat[], seg: number[], total: number, f1: number, f2: number): LngLat[] {
  const a = Math.min(f1, f2),
    b = Math.max(f1, f2)
  const start = pointAtFraction(path, seg, total, a)
  const end = pointAtFraction(path, seg, total, b)
  const mid: LngLat[] = []
  let cum = 0
  for (let i = 0; i < path.length; i++) {
    const frac = total ? cum / total : 0
    if (frac > a && frac < b) mid.push(path[i])
    if (i < seg.length) cum += seg[i]
  }
  return [start, ...mid, end]
}

function resample(coords: LngLat[], stepM: number): LngLat[] {
  if (coords.length < 2) return coords
  const out: LngLat[] = [coords[0]]
  let carry = 0
  for (let i = 1; i < coords.length; i++) {
    let segLen = distM(coords[i - 1], coords[i])
    let from = coords[i - 1]
    while (carry + segLen >= stepM) {
      const need = stepM - carry
      const t = need / segLen
      const np: LngLat = [from[0] + (coords[i][0] - from[0]) * t, from[1] + (coords[i][1] - from[1]) * t]
      out.push(np)
      from = np
      segLen -= need
      carry = 0
    }
    carry += segLen
  }
  out.push(coords[coords.length - 1])
  return out
}

/**
 * Fractional position (0..1) along the dense geometry `path` of each labeled
 * gantry in `points`. Gantries are NOT evenly spaced by path-fraction, so we
 * project each one onto the path rather than assuming index ∝ fraction. The
 * result is forced monotonic non-decreasing (gantries are ordered along the
 * corridor; tiny projection wobble shouldn't reorder them).
 */
function gantryFractions(
  path: LngLat[],
  seg: number[],
  total: number,
  points: { lat: number; lng: number }[],
): number[] {
  const fracs: number[] = []
  let running = 0
  for (const p of points) {
    const f = nearestOnPath(path, seg, total, [p.lng, p.lat]).frac
    running = Math.max(running, f)
    fracs.push(running)
  }
  return fracs
}

export interface LaneMatch {
  corridorId: string
  route: string
  entryLabel: string
  exitLabel: string
  zones: number
  span: LngLat[]
  /** True when the route traverses this corridor in the order of its gantry points
   * (i.e. travel direction = span[0] → span[last]); false when reversed. Lets the
   * caller pick the matching NB/SB/EB/WB direction from the trip geometry. */
  forward: boolean
}

export function matchLanes(routeCoords: LngLat[]): LaneMatch[] {
  if (!routeCoords || routeCoords.length < 2) return []
  const route = resample(routeCoords, SAMPLE_M)
  const matches: LaneMatch[] = []

  for (const g of geoCorridors) {
    const path = (PATHS[g.id] ?? g.points.map((p) => [p.lng, p.lat] as LngLat)) as LngLat[]
    if (path.length < 2) continue
    const { seg, total } = buildCum(path)

    const near = route.map((pt) => {
      const n = nearestOnPath(path, seg, total, pt)
      return { ok: n.dist <= NEAR_M, frac: n.frac, pt }
    })

    // longest contiguous run of "on corridor" route points
    let best: { s: number; e: number; len: number } | null = null
    let i = 0
    while (i < near.length) {
      if (!near[i].ok) {
        i++
        continue
      }
      let j = i
      while (j + 1 < near.length && near[j + 1].ok) j++
      let len = 0
      for (let k = i + 1; k <= j; k++) len += distM(near[k - 1].pt, near[k].pt)
      if (!best || len > best.len) best = { s: i, e: j, len }
      i = j + 1
    }
    if (!best || best.len < MIN_RUN_M) continue

    const f1 = near[best.s].frac
    const f2 = near[best.e].frac
    const forward = f2 >= f1
    const lo = Math.min(f1, f2)
    const hi = Math.max(f1, f2)
    if ((hi - lo) * total < MIN_CORRIDOR_M) continue // route only clips this corridor (e.g. at an interchange)
    const n = g.points.length
    // Snap the matched run to the actual gantries it spans, using each gantry's
    // TRUE fractional position along the dense path (not an even-spacing guess).
    // Entry = last gantry at/before `lo`; exit = first gantry at/after `hi`. This
    // counts every tolled zone the route touches, even when entering mid-zone.
    const gf = gantryFractions(path, seg, total, g.points)
    let idxLo = 0
    for (let k = 0; k < n; k++) if (gf[k] <= lo) idxLo = k
    let idxHi = n - 1
    for (let k = n - 1; k >= 0; k--) if (gf[k] >= hi) idxHi = k
    idxLo = Math.max(0, Math.min(n - 1, idxLo))
    idxHi = Math.max(idxLo, Math.min(n - 1, idxHi))
    const zones = idxHi - idxLo
    if (zones < 1) continue // didn't traverse a full zone — a parallel-freeway clip, not real usage
    const labelLo = g.points[idxLo]?.label ?? g.points[0].label
    const labelHi = g.points[idxHi]?.label ?? g.points[n - 1].label
    matches.push({
      corridorId: g.id,
      route: g.route,
      entryLabel: forward ? labelLo : labelHi,
      exitLabel: forward ? labelHi : labelLo,
      zones,
      span: subPath(path, seg, total, lo, hi),
      forward,
    })
  }

  return matches
}
