// Shareable trip state ↔ querystring, so a fare lookup is a deep link.
import type { Occupancy } from './types'
import type { GeoResult } from './geocode'

export interface TripState {
  corridor: string
  dir: string
  entry: number
  exit: number
  occupancy: Occupancy
  timeMode: 'now' | 'custom'
  minutes: number
  weekend: boolean
}

const OCCS: Occupancy[] = ['solo', 'two', 'threePlus']

export function readTripFromUrl(): Partial<TripState> {
  const q = new URLSearchParams(window.location.search)
  const out: Partial<TripState> = {}
  const c = q.get('c')
  if (c) out.corridor = c
  const dir = q.get('dir')
  if (dir) out.dir = dir
  const from = q.get('from')
  if (from !== null && from !== '' && Number.isFinite(Number(from))) out.entry = Math.max(0, Math.trunc(Number(from)))
  const to = q.get('to')
  if (to !== null && to !== '' && Number.isFinite(Number(to))) out.exit = Math.max(0, Math.trunc(Number(to)))
  const occ = q.get('occ') as Occupancy | null
  if (occ && OCCS.includes(occ)) out.occupancy = occ
  const t = q.get('t')
  if (t === 'now') out.timeMode = 'now'
  else if (t !== null && t !== '' && Number.isFinite(Number(t))) {
    out.timeMode = 'custom'
    out.minutes = Math.min(1439, Math.max(0, Math.trunc(Number(t))))
  }
  if (q.get('we') === '1') out.weekend = true
  return out
}

export function tripToQuery(s: TripState): string {
  const q = new URLSearchParams()
  q.set('c', s.corridor)
  q.set('dir', s.dir)
  q.set('from', String(s.entry))
  q.set('to', String(s.exit))
  q.set('occ', s.occupancy)
  q.set('t', s.timeMode === 'now' ? 'now' : String(s.minutes))
  if (s.weekend) q.set('we', '1')
  return q.toString()
}

export function writeTripToUrl(s: TripState): void {
  const url = `${window.location.pathname}?${tripToQuery(s)}`
  window.history.replaceState(null, '', url)
}

export function shareUrl(s: TripState): string {
  return `${window.location.origin}${window.location.pathname}?${tripToQuery(s)}`
}

// ── Planned address trip (start/end) deep-link ──
export function encodePlan(start: GeoResult, end: GeoResult): string {
  const q = new URLSearchParams()
  q.set('ps', `${start.lng.toFixed(5)},${start.lat.toFixed(5)}`)
  q.set('psl', start.label)
  q.set('pe', `${end.lng.toFixed(5)},${end.lat.toFixed(5)}`)
  q.set('pel', end.label)
  return q.toString()
}

export function readPlanFromUrl(): { start: GeoResult; end: GeoResult } | null {
  const q = new URLSearchParams(window.location.search)
  const ps = q.get('ps')
  const pe = q.get('pe')
  if (!ps || !pe) return null
  const [slng, slat] = ps.split(',').map(Number)
  const [elng, elat] = pe.split(',').map(Number)
  if (![slng, slat, elng, elat].every(Number.isFinite)) return null
  return {
    start: { lng: slng, lat: slat, label: q.get('psl') ?? 'Start' },
    end: { lng: elng, lat: elat, label: q.get('pel') ?? 'Destination' },
  }
}
